INSERT INTO quest_talk (i_num, str_talk) VALUES (44851, 'ВҫГ®ВёВ°ГҖГҢВіВҜГҖГҢ В°Дҹ В°ВЎВҙГҷВҝГ”ВҫГ®ВҝГӨ. ВҫГ®ВёВ°ГҖГҢВҝВЎВ°Г” ВјВұВ№В°ГҮГҸВұГў ГҖВ§ГҮГҳ ВёВ¶В№ДұГҖГҮ ВёВ¶В·Г§В·ГҺ Г„ВөВөДҹ ВёВёВөГ©ВҫГ®ВәВјВұГ®ВҝГӨ? ГҮГҸВіВӘВёВҰ ГҒГҷГ…Г—ВҙГҸВұГ® ГҮГ‘В№Гё ГҮГҳВәВёГҖГҡ~!') ON CONFLICT DO NOTHING;
INSERT INTO quest_talk (i_num, str_talk) VALUES (44852, 'ВҫГ®ВёВ°ГҖГҢВҝВЎВ°Г” ВјВұВ№В°ГҮГҸВұГў ГҖВ§ГҮГҳ ВёВ¶В№ДұГҖГҮ ВёВ¶В·Г§В·ГҺ Г„ВөВөДҹВёВҰ ВёВёВөГ©ВҫГ®ВәВёГҖГҡ! Г„ВөВөДҹГҖГҮ В°ВӯГҲВӯ ВөГ®ВұЕһВҝВЎ ВөГ»В¶Гі ГҒГҒГҖВә ВәВёВ»Гі ГҒГҷГ…Г—ВҙГҸВұГ® ГҮГ‘В№Гё ГҮГҳ ВәВёВјВјВҝГӨ!|ГҒГҹВұЕһ,В°ГӯВұЕһ В°ВӯГҲВӯ ГҒГ–В№В®ВјВӯВёВё В»Г§ВҝГ«ГҮГ‘ ВҫГҶГҖГҢГ…ГӣВёВё ВұВіГҲВҜ В°ВЎВҙГү ГҮГҳВҝГӨ ВІГҖ ВұГўВҫГҜГҮГҳ ГҒГ–ВјВјВҝГӨ.') ON CONFLICT DO NOTHING;
INSERT INTO quest_talk (i_num, str_talk) VALUES (44853, 'ВҫГ®ВёВ°ГҖГҢ ВіВҜГҖГҢ В°Дҹ ВҙГҷВ°ВЎВҝГ”ВҫГ®ВҝГӨ. ВјВіГ…ГҒГҖВ» В°В°ГҖГҢ ВёВёВөГ©ВҫГ® ВәВјВұГ®ВҝГӨ?|ГҒГҹВұЕһ,В°ГӯВұЕһ В°ВӯГҲВӯ ГҒГ–В№В®ВјВӯВёВё В»Г§ВҝГ«ГҮГ‘ ВҫГҶГҖГҢГ…ГӣВёВё ВұВіГҲВҜ В°ВЎВҙГү ГҮГҳВҝГӨ ВІГҖ ВұГўВҫГҜГҮГҳ ГҒГ–ВјВјВҝГӨ.') ON CONFLICT DO NOTHING;
