INSERT INTO quest_talk (i_num, str_talk) VALUES (44859, 'ВјВұВ№В° В»ГіГҖГҡ ВҫГҶГҖГҢГ…ГӣГҖВ» В°ВЎГҒГ¶В°Гӯ ВҝГҖВјГҢВіВӘВҝГӨ? ВҝГёГҮГҸВҙГӮ ВҫГҶГҖГҢГ…ГӣГҖВёВ·ГҺ ВұВіГҲВҜГҮГҳ ВөГҘВёВіВҙГҸВҙГҷ.') ON CONFLICT DO NOTHING;
