INSERT INTO quest_talk (i_num, str_talk) VALUES (44861, 'Are you sure you wish to send your Noah to the Empire Server? Once it is has been sent, you will be unable cancel or reverse it.') ON CONFLICT DO NOTHING;
INSERT INTO quest_talk (i_num, str_talk) VALUES (44862, 'Recently, we saw that El Moradian investigators found a new ore around the guard tower. We attacked and killed one, but the other escaped. We found out that the ore was called [Green Mithril] and can be used to craft a powerful armors. |Karus dispatched troops to the guard tower to take over the [Green Mithril] area but El Morad has already captured the area. We are sending reinforcements to the battle,but it is not so easy due to El Morad''s defenses.') ON CONFLICT DO NOTHING;
INSERT INTO quest_talk (i_num, str_talk) VALUES (44863, 'Karus dispatched troops to the guard tower to take over the [Green Mithril] area but El Morad has already captured the area. We are sending reinforcements to the battle,but it is not so easy due to El Morad''s defenses.') ON CONFLICT DO NOTHING;
INSERT INTO quest_talk (i_num, str_talk) VALUES (44864, 'Will you join us and battle El Morad to recapture the guard tower? | Note: Only enemies who are near  the pillars within the guard tower area will count toward kills.') ON CONFLICT DO NOTHING;
INSERT INTO quest_talk (i_num, str_talk) VALUES (44865, 'You have Slain the enemy troops! Thank you. We hope you will help us again the next time there is an enemy attack.') ON CONFLICT DO NOTHING;
INSERT INTO quest_talk (i_num, str_talk) VALUES (44866, 'We found a new kind of ore around the guard tower. On the way back to our base, we were attacked by Karus troops and one of our investigators was killed and another barely survived. From our spy in Karus, We found out that the ore was called [Green Mithril] and can be used to craft a powerful armors. El Morad has dispatched troops to the guard tower and have built a stronghold around it. |Karus is dispatching their troops to the guard tower to take back the [Green Mithril] area but it is not be easy for them, due to our strong defenses. ') ON CONFLICT DO NOTHING;
INSERT INTO quest_talk (i_num, str_talk) VALUES (44867, 'Karus is dispatching their troops to the guard tower to take back the [Green Mithril] area but it is not be easy for them, due to our strong defenses. ') ON CONFLICT DO NOTHING;
INSERT INTO quest_talk (i_num, str_talk) VALUES (44868, 'Will you join us to defeat Karus and defend the guard tower? | Note: Only enemies who are near  the pillars within the guard tower area will count towards kills.') ON CONFLICT DO NOTHING;
