INSERT INTO quest_talk (i_num, str_talk) VALUES (44871, '7 x [Green Mithril Piece] and 3,000,000 Noah will be used to craft 7th Armor Piece. Which piece of armor do you wish to receive?') ON CONFLICT DO NOTHING;
INSERT INTO quest_talk (i_num, str_talk) VALUES (44872, 'You have brought all the necessary items. I will exchange them for the  armor.') ON CONFLICT DO NOTHING;
INSERT INTO quest_talk (i_num, str_talk) VALUES (44873, 'ВҫГ®ВјВӯВҝГҖВјВјВҝГӨ! ВіВӘГҖГҢГҶВ® ВҝГӮВ¶ГіГҖГҺГҖГҢ 17ГҒГ–ВіГўГҖВ» ВёГӮВҫГ’ВҫГ®ВҝГӨ. ГҮГ—В»Гі ВіВӘГҖГҢГҶВ® ВҝГӮВ¶ГіГҖГҺГҖВ» ВҫГҶВІВё ГҒГ–ВјГ…ВјВӯ В°ВЁВ»Г§ГҮГ•ВҙГҸВҙГҷ. 17ГҒГ–ВіГўГҖВ» ВұГўВіГӨГҮГҸВҙГӮ ГҖГҮВ№ГҢВ·ГҺ ВёВ№ГҖВә ГҖГҢВәВҘГҶВ®ВёВҰ ГҒГҳВәГұГҮГҹВҫГ®ВҝГӨ! ВҫГ®В¶ВІВ°Гү ГҮГҸВҪГғВ°ГҡВҫГ®ВҝГӨ?') ON CONFLICT DO NOTHING;
INSERT INTO quest_talk (i_num, str_talk) VALUES (44874, 'ВөГҘВ·ВЎВ°ГҜГҖГҮ 17ГҒГ–ВіГў ВјВұВ№В° В»ГіГҖГҡВёВҰ В°ВЎГҒГ¶В°Гӯ ВҝГҖВјГҢВіВӘВҝГӨ?') ON CONFLICT DO NOTHING;
INSERT INTO quest_talk (i_num, str_talk) VALUES (44875, 'A """"Baby Dragon"""" has been spotted in Moradon! Please bring 10 """"Orange Scented Onions"""" that drop once you defeat the baby dragon.') ON CONFLICT DO NOTHING;
INSERT INTO quest_talk (i_num, str_talk) VALUES (44876, 'ВҝГҖВ·В»ГҒГ¶ГҮГў ВҫГ§ГҶГ„""""ВёВҰ 10В°Ві В°ВЎГҒВ®ВҙГҷ ГҒГ–ВҪГғВёГ© ВҙГҷВҫГ§ГҮГ‘ ВҫГҶГҖГҢГ…ГӣГҖВ» ВјВұВ№В°В·ГҺ ВөГҘВ·ГҒВҝГӨ! В°ВЎГҒВ®ВҙГҷ ГҒГ–ВҪГғВ°ГҡВҫГ®ВҝГӨ?') ON CONFLICT DO NOTHING;
INSERT INTO quest_talk (i_num, str_talk) VALUES (44877, 'ВҫГҲВіГ§ГҮГҸВјВјВҝГӨ! ВәВ№ВәГ’ВәВ№ Г„Г№ВҪВәГҶВ®ВҙГӮ Г„Г№ВҪВәГҶВ® ГҮГҸВіВӘВёВҰ ВҝГҸВ·ГЎ ГҮГҸВҪГғВёГ© В·ВЈВҙДұГҖВёВ·ГҺ Г„Г№ВҪВәГҶВ®ВёВҰ ГҮГҸВіВӘ ВҙГөВөГҘВ·ГҒВҝГӨ! В·ВЈВҙДұГҖВёВ·ГҺ Г„Г№ВҪВәГҶВ®ВёВҰ В№ЕһГҖВёВҪГ… ВіВ»ВҝГ«ВҝВЎ ВөГ»В¶ГіВјВӯ Г…ГӮВҫГ§ГҖГҮВәГ» or 17ГҒГ–ВіГў ВјВұВ№В° В»ГіГҖГҡВёВҰ ВөГҘВёВ®В°Гӯ ГҖГ–ВҫГ®ВҝГӨ!') ON CONFLICT DO NOTHING;
INSERT INTO quest_talk (i_num, str_talk) VALUES (44878, 'ВёГ•ГҖГә ГҶГ„В¶ГіВ№В®, ВөГ’ ВјГ–ГҒВ®, ГҶВ®В·Г‘ В№Г¶ВјВӯГ„Вҝ, ГҖГҡГҖГҢВҫДҹГҶВ® В°ГұВ·ВҪ В°Вў 10ВёВ¶ВёВ®ВҫВҝ ГҖГўВҫГҶВҝГҚ ГҒГ–ВҪГғВ°ГҡВҫГ®ВҝГӨ?') ON CONFLICT DO NOTHING;
INSERT INTO quest_talk (i_num, str_talk) VALUES (44879, 'ГҖГўВҫГҶ ВҝГҖВјГҢВұВәВҝГӨ! ВұГ—В·Ві В·ВЈВҙДұ Г„Г№ВҪВәГҶВ®ВёВҰ ВөГҘВёВұВІВІВҝГӨ!|*ГҮГ‘В№Гё В·ВЈВҙДұ Г„Г№ВҪВәГҶВ®ВёВҰ В№ЕһГҖВёВҪГ… ГҲГ„ ГҶГ·ВұГўГҮГҸВҪГғВёГ© ВҙГҷВҪГғ Г„Г№ВҪВәГҶВ®ВёВҰ В№ЕһГҖВёВҪГҮ ВјГ¶ ВҫГёВҪГҖВҙГҸВҙГҷ.') ON CONFLICT DO NOTHING;
