INSERT INTO quest_talk (i_num, str_talk) VALUES (44888, 'ВҙГңВҝГҖ ГҖГҢВәВҘГҶВ® ГҒГёГҮГ  ГҒГҹГҖГҢВҝВЎВҝГӨ!В°ВіГғВҙ ГҒГ¶ВҝВӘВҝВЎВјВӯ ГҖГ»ВұВ№ ГҖВҜГҖГәВёВҰ ГғВіГ„ВЎГҮГ‘ВёГ© ВҙГңВҝГҖ ГҒГ–ВёГ“ВҙГҸВёВҰ ГҲВ®ВөГҰГҮГ’ ВјГ¶ ГҖГ–В°Гӯ 25В°ВіВёВҰ ВёДҹВҫГҶ В·ВЈВҙДұГҖВёВ·ГҺ ВҙГҷВҫГ§ГҮГ‘ ВәВёВ»ГіГҖВ» ВұВіГҲВҜГҮГ’ ВјГ¶ ГҖГ–ВҪГҖВҙГҸВҙГҷ.') ON CONFLICT DO NOTHING;
