INSERT INTO quest_talk (i_num, str_talk) VALUES (44930, 'ВҝВӨВёДҹВ¶ГіВөГҘ ГҖГјВҝГ« ГҖГҢВөВҝ В°Г”ГҖГҢГҶВ®ГҖГ”ВҙГҸВҙГҷ. ГҒГ¶ГҒВӨВөГҲ ГҒГӮГҮВҘВ·ГҺ ГҖГҢВөВҝ ГҮГҸВҪГғВ°ГҡВҪГҖВҙГҸВұГ®?') ON CONFLICT DO NOTHING;
