INSERT INTO quest_talk (i_num, str_talk) VALUES (44970, 'ВҪВәГҶГӨВјГҲ ВҪВәГҖВ§Г„ВӘ ГҮГҒВёВ®В№ГҢВҫГ¶ГҖВ» ГҖГ»ВҝГ« ГҮГҸВҪГғВ°ГҡВҪГҖВҙГҸВұГ®? ГҖГ»ВҝГ«ГҖВ» ГҮГҸВұГў ГҖВ§ГҮГҳ Г…В¬В¶ГіГҖГҢВҫДҹГҶВ®В°ВЎ ГҒВҫВ·ГЎ ВөГӢВҙГҸВҙГҷ.') ON CONFLICT DO NOTHING;
INSERT INTO quest_talk (i_num, str_talk) VALUES (44971, 'ВҪВәГҶГӨВјГҲ ВҪВәГҖВ§Г„ВӘ ГҮГҒВёВ®В№ГҢВҫГ¶ГҖВ» В°В®В°Гӯ ГҖГ–ГҒГ¶ ВҫГҠГҖВёВҪГғВұВәВҝГӨ. ГҖГҺВәВҘГ…ГӨВёВ®ВёВҰ ГҲВ®ГҖГҺГҮГҳ ГҒГ–ВјВјВҝГӨ. EX ГҮГҒВёВ®В№ГҢВҫГ¶ГҖВә ГҶГ„ВҝГ¶ВјВҘВҝВЎВјВӯ ВұВёВёГ…В°ВЎ В°ВЎВҙГүГҮГ•ВҙГҸВҙГҷ.') ON CONFLICT DO NOTHING;
INSERT INTO quest_talk (i_num, str_talk) VALUES (44972, 'Hail Ultima! The Brotherhood is in need of [Lunar Order Token]. Do you have any for me? I have much to offer.') ON CONFLICT DO NOTHING;
INSERT INTO quest_talk (i_num, str_talk) VALUES (44973, 'ВұГ—ВёВ° В№ГҢВҪВәВёВұ ГҒВ¶В°Вў 2В°ВіВ·ГҺ 7ГӮГ· В№ГҰВҫГ®ВұВё 1В°ВіВ·ГҺ ВұВіГҲВҜГҮГҳВөГҘВёВіВҙГҸВҙГҷ. ВҫГ®В¶В°ГҮГ‘ В№ГҰВҫГ®ВұВёВёВҰ ВҝГёГҮГҸВҪГғВіВӘВҝГӨ?') ON CONFLICT DO NOTHING;
INSERT INTO quest_talk (i_num, str_talk) VALUES (44974, 'ВәДһГҲВ«В»Г¶ ВјГӣГҶГӯГҖВә Г„ВіВёВҜГ…ГҚ В·В№ВәВ§ 70ГҖГҢВ»ГіВёВё ВјГ¶В·Гү ГҮГҸВҪГҮ ВјГ¶ ГҖГ–ВҪГҖВҙГҸВҙГҷ.') ON CONFLICT DO NOTHING;
INSERT INTO quest_talk (i_num, str_talk) VALUES (44975, 'В¶ГіГ…Г—ГҖГҢВіГ« В·Г©ГҖВ» ВұВіГҲВҜГҮГҳ ВөГҘВёВ®В°Гӯ ГҖГ–ВҪГҖВҙГҸВҙГҷ. ВёГ® В°ВіВ·ГҺ ВұВіГҲВҜ ГҮГҸВҪГғВ°ГҡВҪГҖВҙГҸВұГ®?') ON CONFLICT DO NOTHING;
INSERT INTO quest_talk (i_num, str_talk) VALUES (44976, 'В¶ГіГ…Г—ГҖГҢВіГ« В·Г©ГҖГҢ ВҫГёВҪГҖВҙГҸВҙГҷ. ГҖГҺВәВҘГ…ГӨВёВ®ВёВҰ ГҲВ®ГҖГҺ ГҮГҳ ГҒГ–ВјВјВҝГӨ.') ON CONFLICT DO NOTHING;
INSERT INTO quest_talk (i_num, str_talk) VALUES (44977, 'ГҒВӨВ·ГүГҖГҮ ВјВұВ№В°ГҮГ”""""ГҖВ» ВұВіГҲВҜГҮГҳ ВөГҘВёВ®В°Гӯ ГҖГ–ВҪГҖВҙГҸВҙГҷ. ВұВіГҲВҜГҖВ» ГҖВ§ГҮГҳВјВӯВҙГӮ ГҖГҺВәВҘГ…ГӨВёВ® 4Г„ВӯГҖВ» ВәГұВҝГ¶ГҒГ–ВјГ…ВҫГҹ ВұВіГҲВҜГҮГҳ ВөГҘВёВіВҙГҸВҙГҷ.|ВұВіГҲВҜГҮГҸВҪГғВ°ГҡВҪГҖВҙГҸВұГ®?') ON CONFLICT DO NOTHING;
INSERT INTO quest_talk (i_num, str_talk) VALUES (44978, 'ГҖГҺВәВҘГ…ГӨВёВ®ВҝВЎ """"ГҒВӨВ·ГүГҖГҮ ВјВұВ№В°ГҮГ”""""ГҖГҢ ВҫГёВҪГҖВҙГҸВҙГҷ, ГҖГҺВәВҘГ…ГӨВёВ®ВёВҰ ГҲВ®ГҖГҺГҮГҳГҒГ–ВјВјВҝГӨ') ON CONFLICT DO NOTHING;
INSERT INTO quest_talk (i_num, str_talk) VALUES (44979, 'ГҖГҺВәВҘГ…ГӨВёВ®ВҝВЎ 4Г„Вӯ ГҖГҢВ»Гі В°ГёВ°ВЈГҖВ» ВәГұВҝГ¶ГҒГ–ВҪГғВ°Гӯ ВҙГҷВҪГғ ВұВіГҲВҜГҮГҳГҒГ–ВјВјВҝГӨ.') ON CONFLICT DO NOTHING;
INSERT INTO quest_talk (i_num, str_talk) VALUES (44980, 'ВҫГҲВіГ§ГҮГҸВјВјВҝГӨ ВҫГҶВөВөВҙГҸВөГҘВҙГ«В·ГәВ°Гә ВҙГҷВёВҘГӮГ·ВҝГёГҖГҮ ГҶГӨГҖГҢВҪВәВәГҸ, ГҖВҜГҶВ©ВәГӘВёВҰ ВҝВ¬В°ГЎГҮГҳГҒГ–ВҙГӮ [SNS]ГҶГӨГҖГҢВҪВәГҖГ”ВҙГҸВҙГҷ. ВҫГ®В¶ВІ SNSВ·ГҺ ГҖГҢВөВҝГҮГҸВҪГғВ°ГҡВҪГҖВҙГҸВұГ®?') ON CONFLICT DO NOTHING;
INSERT INTO quest_talk (i_num, str_talk) VALUES (44981, 'ВҫГҶВөВөВҙГҸВҪВә ВҙГ«В·ГәВ°Гә ВҙГҷВёВҘ ГӮГ·ВҝГёГҖГҮ ГҖВҜГҶВ©ВәГӘВёВҰ ВҝВ¬В°ГЎГҮГҳГҒГ–В°Гӯ ГҖГ–ВҪГҖВҙГҸВҙГҷ. ГҖВҜГ…ГөВәГҺВёВҰ ВҝВӯВҫГ® ГҒГ–ВҪГҮВ°ГҰВҝГ¬ ВәВёВ»ГіГҖВ» ВөГҘВёВ®В°Гӯ ГҖГ–ВҪГҖВҙГҸВҙГҷ! ВёВ№ГҖВә ГӮГјВҝВ© ВәГҺГ…В№ВөГҘВёВ®В°ГҡВҪГҖВҙГҸВҙГҷ.') ON CONFLICT DO NOTHING;
INSERT INTO quest_talk (i_num, str_talk) VALUES (44982, 'ВҫГҶВөВөВҙГҸВҪВә ВҙГ«В·ГәВ°Гә ВҙГҷВёВҘ ГӮГ·ВҝГёГҖГҮ ГҶГӨГҖГҢВҪВәВәГҸГҖВ» ВҝВ¬В°ГЎГҮГҳГҒГ–В°Гӯ ГҖГ–ВҪГҖВҙГҸВҙГҷ. ГҶГӨГҖГҢВҪВәВәГҸГҖВ» ВҝВӯВҫГ® ГҒГ–ВҪГҮВ°ГҰВҝГ¬ ВәВёВ»ГіГҖВ» ВөГҘВёВ®В°Гӯ ГҖГ–ВҪГҖВҙГҸВҙГҷ! ВёВ№ГҖВә ГӮГјВҝВ© ВәГҺГ…В№ВөГҘВёВ®В°ГҡВҪГҖВҙГҸВҙГҷ.') ON CONFLICT DO NOTHING;
INSERT INTO quest_talk (i_num, str_talk) VALUES (44983, 'ВҫГҶГҒГ·ВөВө ГҖВҜГҶВ©ВәГӘВёВҰ ГҖГҢВҝГ«ГҮГҳВәВ» ГҖГ»ГҖГҢ ВҫГёВҙГҷВұВёВҝГӨ? ГҖГҢВ·Вұ... ВұГ—В·ВҜВҙГҷВ°ВЎ ВҪГғВҙГ«ВҝВЎ ВөГҡГғВіГҒГ¶ВҙГӮ ВјГ¶В°ВЎ ГҖГ–ВҪГҖВҙГҸВҙГҷ. ВұГ—В·ВҜГҒГ¶ ВёВ»В°Гӯ ГҒВҰВ°ВЎ ВҝВ¬В°ГЎГҮГҳ ВөГҘВёВұ Г…Г—ВҙГҸ ГҮГ‘ В№Гё ВөГ©ВҫГ®В°ВЎ ВәВёВҙГӮВ°Г” ВҫГ®В¶ВІВ°ВЎВҝГӨ? ВөГҺВ·ГҒВҝГ¶ ГҮГҸГҒГ¶ ВёВ¶ВҪГғВ°Гӯ ГҮГ‘В№ГёВёВё ГҖГҢВҝГ« ГҖГҹГҮГҳВәВёВёГ© ГҒВҰВ°ВЎ ВәВёВ»ГіГҖВ» ВөГҘВёВіВҙГҸВҙГҷ.!') ON CONFLICT DO NOTHING;
INSERT INTO quest_talk (i_num, str_talk) VALUES (44984, 'ВөВҝГҖГҸ IPВ·ГҺ ГҖГ”ГҖГҘВөГҲ Г„ВіВёВҜГ…ГҚВ°ВЎ ГҖГ–ВҪГҖВҙГҸВҙГҷ.') ON CONFLICT DO NOTHING;
INSERT INTO quest_talk (i_num, str_talk) VALUES (44985, 'ГҖГҢВ№ГҢ ВҫГҶГҖГҢГ…ГӣГҖВ» В№ЕһВҫГҶ В°ВЎВјГҢВҪГҖВҙГҸВҙГҷ.') ON CONFLICT DO NOTHING;
