INSERT INTO quest_talk (i_num, str_talk) VALUES (44994, 'ВҫГҶГҒГ· ГҮГ‘В№ГёВөВө ГҖВҜГҶВ©ВәГӘГҖВ» ГҖГҢВҝГ«ГҮГҳ ВәВ»ГҖГ»ГҖГҢ ВҫГёВҙГҷВұВёВҝГӨ? ГҖГҢВ·Вұ.. ВұГ—В·ВҜВҙГҷВ°ВЎ ВҪГғВҙГ«ВҝВЎ ВөГҡГғВіГҒГ¶ВҙГӮ ВјГ¶В°ВЎ ГҖГ–ВҪГҖВҙГҸВҙГҷ. ВұГ—В·ВҜГҒГ¶ ВёВ»В°Гӯ ГҒВҰВ°ВЎ ВҝВ¬В°ГЎГҮГҳ ГҒГҷ Г…Г—ВҙГҸ ГҮГ‘ В№Гё ВөГ©ВҫГ®В°ВЎ ВәВёВҙГӮВ°Г” ВҫГ®В¶ВІВ°ВЎВҝГӨ? ВөГҺВ·ГҒВҝГ¶ ГҮГҸГҒГ¶ ВёВ¶ВјВјВҝГӨ. ГҮГ‘В№ГёВёВё ГҖГҢВҝГ« ГҖГҹ ГҮГҳВәВёВёГ© ГҒВҰВ°ВЎ ВҝВҘВәГӯВ·ВіГҖВ» ВјВұВ№В°В·ГҺ ВөГҘВёВұВ°Г”ВҝГӨ.') ON CONFLICT DO NOTHING;
