INSERT INTO quest_talk (i_num, str_talk) VALUES (45009, 'В¶ГіГ…Г—ГҖГҢВіГ«В·Г©ГҖГҢ ГҖГҺВәВҘГ…ГӨВёВ®ВҝВЎ ВёВ№ГҖГҢ ВјГ’ГҒГ¶ГҮГҸВ°Гӯ ГҖГ–ВҪГҖВҙГҸВҙГҷ. |ГҖГҺВәВҘГ…ГӨВёВ® ВҫГ•ГӮГҠВҝВЎ ГҖГ–ВҙГӮ В¶ГіГ…Г—ГҖГҢВіГ«В·Г©ГҖГҢ ВұВіГҲВҜ ГҲГ„ В°ВіВјГ¶В°ВЎ 9999В°ВіВ°ВЎ ГғГҠВ°ГәВөГҮВёГ© ВұВіГҲВҜ ГҮГҸВҪГҮВјГ¶ ВҫГёВҪГҖВҙГҸВҙГҷ. |ВұГ—В·ВЎВөВө ВұВіГҲВҜ ГҮГҸВҪГғВ°ГҡВҪГҖВҙГҸВұГ®?') ON CONFLICT DO NOTHING;
INSERT INTO quest_talk (i_num, str_talk) VALUES (45010, 'В¶ГіГ…Г—ГҖГҢВіГ«В·Г© ВұВіГҲВҜ ГҲГ„ ГҖГҺВәВҘГ…ГӨВёВ® ВҫГ•ГӮГҠГҖГҮ В¶ГіГ…Г—ГҖГҢВіГ«В·Г©ГҖГҢ 9999В°ВіВ°ВЎ ГғГҠВ°Гә ВөГҮВҫГәВҪГҖВҙГҸВҙГҷ В¶ГіГ…Г—ГҖГҢВіГ«В·Г©ГҖВ» ВјГ’ВёДҹ ГҲГ„ ВҙГҷВҪГғ ВұВіГҲВҜГҮГҳГҒГ–ВјВјВҝГӨ') ON CONFLICT DO NOTHING;
