INSERT INTO quest_talk (i_num, str_talk) VALUES (45014, 'ВҫГҲВіГ§ГҮГҸВјВјВҝГӨ! 2020ВіГў ВјВіВіВҜГҖГҢ ВҝГ”ВҪГҖВҙГҸВҙГҷ! |ВҫГ®В¶В°ГҮГ‘ ВјВіВіВҜ ГҖГҢВәВҘГҶВ®ВёВҰ ГҒГёГҮГ  ГҮГҸВҪГғВ°ГҡВҪГҖВҙГҸВұГ®?') ON CONFLICT DO NOTHING;
INSERT INTO quest_talk (i_num, str_talk) VALUES (45015, 'ВёЕһВҙГҸВҪГғВҫГҶВҝВЎВ°Г” ГҶВјГ„ГҸГҖВ» В№ЕһВҫГҶ ВҝГҖВјГҢВіВӘВҝГӨ? |ВёЕһВҙГҸВҪГғВҫГҶВҝВЎВ°Г” В°ВЎВјГ…ВјВӯ """"ГҖГңВјГ’ВёВ® ГҖВҜВ·ГүГҖГҢ ВіВӘГ…ВёВіВөВҙГҷ"""" Г„Г№ВҪВәГҶВ®ВёВҰ ВҝГҸВ·ГЎГҮГҸВҪГғВёГ© ГҶВјГ„ГҸГҖВ» В№ЕһГҖВё ВҪГҮ ВјГ¶ ГҖГ–ВҪГҖВҙГҸВҙГҷ.') ON CONFLICT DO NOTHING;
INSERT INTO quest_talk (i_num, str_talk) VALUES (45016, 'ГҶВјГ„ГҸГҖВ» В°ВЎГҒГ¶В°Гӯ ВҝГҖВјГҢВұВәВҝГӨ!! ГҶВјГ„ГҸГҖВ» ГҖГҢВҝГ«ГҮГҸВҝВ© 2В°ВЎГҒГ¶ Г„Г№ВҪВәГҶВ®ВёВҰ ВјВіВёГӯ ВөГҘВёВ®В°ГҡВҪГҖВҙГҸВҙГҷ|1.ГҖГҢВҪВҪВ¶ГөГҶВ® В°ГҰГҮГЁГ„ВЎГҖГҮ ГғГ ВәВ№ - ГҖГҢВҪВҪВ¶ГөГҶВ®ГҖГҮ ВёГіВҪВәГ…ГҚ 5ГҒВҫГҖВ» В°Вў В°Вў 5ВёВ¶ВёВ®ВҫВҝ ГҖГўВҫГҶ ВҝГҖВҪГғВёГ© В°ГҰГҮГЁГ„ВЎ 1ВҫГҜВ°Гә ВҙЕһГҖГҮ Г…ВёГ…Гө 1ГҖГҸГҖВ» ВөГҘВёВ®В°Гӯ ГҖГ–ВҪГҖВҙГҸВҙГҷ |2.ГҲГұВұГҚГҮГ‘ В·В№ВөГҘ ВөГҘВ·ВЎВ°ГҜ В»Г§ВіГү - ГҲГұВұГҚГҮГ‘ В·В№ВөГҘВөГҘВ·ВЎВ°ГҜГҖВ» ГҖГўГҖВёВјГ…ВјВӯ """"ГҲГұВұГҚГҮГ‘ В·В№ВөГҘВөГҘВ·ВЎВ°ГҜГҖГҮ ВҪГүГҖГҘ""""ГҖВ» В°ВЎГҒВ®ВҝГҖВҪГғВёГ© """"ВұД°Г…Г—ВөГҺВёВҘ ВәВ№ГҒГ–ВёГ“ВҙГҸВёВҰ ВөГҘВёВ®В°Гӯ ГҖГ–ВҪГҖВҙГҸВҙГҷ"""" |ВҫГ®В¶В°ГҮГ‘ Г„Г№ВҪВәГҶВ®ВёВҰ ГҒГёГҮГ  ГҮГҸВҪГғВ°ГҡВҪГҖВҙГҸВұГ®? |Г„Г№ВҪВәГҶВ®ВёВҰ ГҮГ‘В№Гё В№ЕһГҖВёВҪГғВёГ© ГҶГ·ВұГўГҮГҸВҪГҮВјГ¶ ВҫГёГҖВёВҪГғВёГ§, Г„Г№ВҪВәГҶВ® Г…В¬ВёВ®ВҫГ® ВҝВ©ВәГҺ В»ГіВ°ГјВҫГёГҖГҢ ВҙГҷГҖВҪВіВҜ ГғГҠВұГўГҲВӯ ВөГӢВҙГҸВҙГҷ.') ON CONFLICT DO NOTHING;
