INSERT INTO quest_talk (i_num, str_talk) VALUES (45018, 'ГҲГұВұГҚГҮГ‘ ВҙГҷГ…В©ВөГҘВ·ВЎВ°ГҜ В»Г§ВіГүГҖВ» ВјВұГ…Гғ ГҮГҸВјГҢВұВәВҝГӨ! |ВёГ…ГҖГҸ """"ГғГ ВәВ№В№ЕһГҖВә ВјГ’ВіГ """"ВёВҰ Г…Г«ГҮГҳВјВӯ В·В№ВәВ§ 80ГҖГҢВ»ГіГҖГҮ ГҖВҜГҖГәВөГ© ГҒГҹ 12ВҪГғ 40ВәДһ, 22ВҪГғ 30ВәДһВҝВЎ ГҖГ”ГҖГҘ В°ВЎВҙГүГҮГҸВёГ§, ВјВұГӮГёВјГё 150ВёГӯВұГ®ГҒГ¶ ГҖГ”ГҖГҘ В°ВЎВҙГүГҮГ‘ ГҖГҢВәВҘГҶВ® ВұВёВҝВӘГҖГ”ВҙГҸВҙГҷ |В¶ГҮГҮГ‘ ГҖГҢ Г„Г№ВҪВәГҶВ®ВҙГӮ В°ГЁГҒВӨВҙГ§ ГҮГ‘В№ГёВёВё ГҮГғВ·В№ГҖГҢ ГҮГҸВҪГҮ ВјГ¶ ГҖГ–ГҖВёВҪГғВёГ§, ГҖГҢ ВұВёВҝВӘВҝВЎ ГҮГ‘В№Гё ВөГ©ВҫГ®В°В¬ВҙГҷВ°ВЎ ГҒГ—ГҖВёВҪГғВ°Г…ВіВӘ, ГҒГ·ГҒВў ВұВёВҝВӘГҖВ» ВіВӘВҝГҖВјГ…ВөВө ВҙГҷВҪГғ ВөГ©ВҫГ®В°ВЎВҪГҮ ВјГ¶ ВҫГёВҪГҖВҙГҸВҙГҷ. ГҒГ–ГҖГҮГҮГҳ ГҒГ–ВҪГғВұГҰ В№ГҷВ¶ГёВҙГҸВҙГҷ. ') ON CONFLICT DO NOTHING;
INSERT INTO quest_talk (i_num, str_talk) VALUES (45019, 'ГҲГұВұГҚГҮГ‘ В·В№ВөГҘВөГҘВ·ВЎВ°ГҜГҖВ» В»Г§ВіГүГҮГҸВҝВ©ВјВӯ """"ГҲГұВұГҚГҮГ‘ В·В№ВөГҘВөГҘВ·ВЎВ°ГҜГҖГҮ ВҪГүГҖГҘ""""ГҖВ» ГҖГәВҝВЎВ°Г” В°ВЎГҒГ¶В°Гӯ ВҝГҖВҪГғВёГ© """"ВұД°Г…Г—ВөГҺВёВҘ ВәВ№ГҒГ–ВёГ“ВҙГҸ""""ВёВҰ ВәВёВ»ГіГҖВёВ·ГҺ ВөГҘВёВ®В°ГҡВҪГҖВҙГҸВҙГҷ! |ВөВөГҖГј ГҮГҸВҪГғВ°ГҡВҪГҖВҙГҸВұГ®? |<font color=@#660066@> ГҲГұВұГҚГҮГ‘ В·В№ВөГҘВөГҘВ·ВЎВ°ГҜГҖВ» ГғВіГ„ВЎВҪГғ ВіВ·ГҖВә ГҲВ®В·ГјВ·ГҺ В°ГӢГҖВә ВәВёВ№В°В»ГіГҖГҡВ°ВЎ ГҒГ–ГҖВ§ ГҖВҜГҖГә 5ВёГӯВҝВЎВ°Г” В·ВЈВҙДұГҖВёВ·ГҺ ГҒГ¶ВұЕһ ВөГӢВҙГҸВҙГҷ!') ON CONFLICT DO NOTHING;
