INSERT INTO quest_talk (i_num, str_talk) VALUES (45061, 'ВҫГҲВіГ§ГҮГҸВјВјВҝГӨ~ [ГҖГҢВәВҘГҶВ® В°ГјВёВ®ГҖГҺ] ВҫГҶВјГӮ ГҖГ”ВҙГҸВҙГҷ. ГҒГҳВәГұВөГҲ ГҖГҢВәВҘГҶВ®В°ВЎ ГҒВҫВ·ГЎ ВөГҮВҫГ®ВјВӯ ГҮГ¶ГҖГ§ ГҒГёГҮГ ГҒГҹГҖГҺ ГҖГҢВәВҘГҶВ®В°ВЎ ВҫГёВҪГҖВҙГҸВҙГҷ.') ON CONFLICT DO NOTHING;
INSERT INTO quest_talk (i_num, str_talk) VALUES (45062, 'ГҖГҡВіГ— ВҪГ…ГҖГҘГҖГҮ ВұГўВөВөВ№В®ГҖГҢВ¶ГіВ°Гӯ ВҫГӢВ°Гӯ ГҖГ–ВҙГӮВ°ВЎ? |ВёДҹВөГ§ ГҒГ¶ВҝВӘ ГҖГўГҲВӯВ»ГіГҖГҺВҝВЎВ°Г” В»Г§ГҒВҰ ГҖГјВҝГ« ВҫГҶГҖГҢГ…ГӣГҖВ» ГҶГҮВёГ…ГҮГҸВ°Гӯ ГҖГ–ВҙГӮВ°Гү ВҫГӢВ°Гӯ ГҖГ–ВҙГӮВ°ВЎ? В°Г…ВұГўВҝВЎ ВҙГ«ГҮГҳ В°ВЈВҙГңГҮГ‘ ВјВіВёГӯГҖВ» ГҮГҳГҒГ–В°ГҡВіГ—, ВЎВ°ВҪГ…ГҖГҘГҖГҮ ВұГўВөВөВ№В® В°Гә Г…В©В·ГҺВіГ«ВҪВә ВұГўВөВөВ№В®ВЎВұГҖГҢВ¶ГіВҙГӮ ВҫГҶГҖГҢГ…ГӣГҖГҢ ГҖГ–ВҙГӮВөВҘ ВЎВ°ВҪГ…ГҖГҘГҖГҮ ВұГўВөВөВ№В®ВЎВұГҖВә В°ГёВ°Д°В·ГӮГҖВ» 50% ВҝГғВ·ГҒГҒГ–В°Гӯ, ВЎВ°Г…В©В·ГҺВіГ«ВҪВә ВұГўВөВөВ№В®ВЎВұГҖВә В°ГёВ°Д°В·ГӮГҖВ» 20% ВҝГғВ·ГҒГҒГ–ВҙГӮ ВҫГҶГҖГҢГ…ГӣГҖГҢВ¶ГіВіГ—, ВөГҺВ°ВіГҖГҮ ВҫГҶГҖГҢГ…ГӣГҖГҮ ГҒГ¶ВјГ“ВҪГғВ°ВЈГҖВә 3ВәДһВөВҝВҫГҲ В»Г§ВҝГ«ГҮГ’ ВјГ¶ ГҖГ–ВҙГҷВіГ— ВіВӘВҝВЎВ°Г” ВЎВ°ВҪГ…ГҖГҘГҖГҮ ВұГўВөВөВ№В®ВЎВұ ГҮГҸВіВӘВёВё В°ВЎГҒГ¶В°Гӯ ВҝГҚГҒГ–В°ГҡВіВӘ?') ON CONFLICT DO NOTHING;
INSERT INTO quest_talk (i_num, str_talk) VALUES (45063, '[ВјГ¶ВёВ® ГҖГўГҲВӯГҒВЎ]ВҝВЎВјВӯ ВұВёГҮГ’ ВјГ¶ ГҖГ–ВҙГҷВіГ— В°ВЎВјВӯ """"ВҪГ…ГҖГҘГҖГҮ ВұГўВөВөВ№В®"""" ГҮГҸВіВӘВёВё В»Г§ В°ВЎГҒГ¶В°Гӯ ВҝГҚГҒГ–В°ГҡВіВӘ?') ON CONFLICT DO NOTHING;
INSERT INTO quest_talk (i_num, str_talk) VALUES (45064, 'ВұГ—В·Вё....ВұВёВёВё, ВҫГҶВҪВұГҒГ¶ВёВё ГҮГҸВҙГӮ ВјГ¶ ВҫГёГҒГ¶ В»ДұВ°ВўГҖГҢ В№ГҷВІГ®ВёГ© ВҙГҷВҪГғ ВҝГҖВ°Г”ВіВӘ') ON CONFLICT DO NOTHING;
INSERT INTO quest_talk (i_num, str_talk) VALUES (45065, 'ГҖГҡВіГ— ГҖГҺВәВҘГ…ГӨВёВ®ВҝВЎ ВҫГҶГҒГ· ВҪГ…ГҖГҘГҖГҮ ВұГўВөВөВ№В®ГҖГҢ ВҫГёВҙГҷВіГ—, [ВјГ¶ВёВ® ГҖГўГҲВӯГҒВЎ]ВҝВЎВ°Г” В°ВЎВјВӯ ГҮГҸВіВӘВёВё В°ВЎГҒГ¶В°Гӯ ВҝГҚВјВӯ ВҙГҷВҪГғ ВёВ»ГҖВ» В°ГүВ°Г”ВіВӘ') ON CONFLICT DO NOTHING;
INSERT INTO quest_talk (i_num, str_talk) VALUES (45066, 'ВұВёГҮГҳВҝГ”ВұВёВёВё! В»Г§ВҝГ« В№ГҰВ№ДұГҖВә ВҫГҶГҖГҢГ…ГӣГғВіВ·Ві В»Г§ВҝГ« ГҮГҸВ°Г…ВіВӘ, ВҪВәГ…ВіГғВўВҝВЎ ГҖГ–ВҙГӮ ВҪВәГ…ВіГҖВ» В»Г§ВҝГ« ГҮГҸВөГӯГҖГҢ В»Г§ВҝГ«ГҮГҸВёГ© ВөГҲВҙГҷВіГ—! ВҝВ©ВұГў ВәВёВ»ГіГҖВ» ГҒГ–В°ГҡВіГ—!') ON CONFLICT DO NOTHING;
INSERT INTO quest_talk (i_num, str_talk) VALUES (45067, 'ГҖГҺВәВҘГ…ГӨВёВ®ВҝВЎ В№В» ВіГ–В°Гӯ ВҙГҷВҙГҸВҙГӮВ°Г•В°ВЎ В°ГёВ°ВЈГҖВ» ГҲВ®ВәВёГҮГҸВ°Гӯ ВҝГҖВ°Г”ВіВӘ') ON CONFLICT DO NOTHING;
INSERT INTO quest_talk (i_num, str_talk) VALUES (45068, 'ВҫГҲВіГ§ГҮГҸВјВјВҝГӨ ГҖГәВёВҰ ГғВЈГҖВёВјГҢВіГ—ВҝГӨ! |5ГӮГ· В№ГҰВҫГ®ВұВё +5ГӮВҘВёВ® ГҒГ·ВҫГ·ВәВ°В·ГҺ ВҙГң ГҮГ‘В№Гё! 5ВәГҺГҖВ§ВёВҰ ГҶГҮВёГ…ГҮГҸВ°ГӯГҖГ–ВҪГҖВҙГҸВҙГҷ! ГҶГҮВёГ… ВұД°ВҫГ—ГҖВә ВәГҺГҖВ§ВҙГ§ 180ВёВёВіГ«ВҫГҶ~220ВёВё ВіГ«ВҫГҶГҒГҹ В·ВЈВҙДұГҖВёВ·ГҺ ВұВёВёГ…В°ВЎВҙГүГҮГ•ВҙГҸВҙГҷ!') ON CONFLICT DO NOTHING;
INSERT INTO quest_talk (i_num, str_talk) VALUES (45069, 'ВҫГ®ВҙГҖ ГҒГ·ВҫГ·ВұВәГҖГҮ 5ГӮГ· В№ГҰВҫГ®ВұВёВёВҰ ВұВёВёГ… ГҮГҸВҪГғВ°ГҡВҪГҖВҙГҸВұГ®? |ГғГ–ВҙГ« ВұВёВёГ… ВұД°ВҫГ—ГҖГҺ 1100ВёВё ВіГ«ВҫГҶВёВҰ ВјГ’ГҒГ¶ГҮГҸВ°Гӯ ГҖГҺВәВҘГ…ГӨВёВ® 5Г„ВӯГҖВ» ВәГұВҝГ¶ВөГҺВјГ…ВҫГҹ ВұВёВёГ…В°ВЎ В°ВЎВҙГүГҮГ•ВҙГҸВҙГҷ! |ГҖГәВҙГӮ ГғГўГҮГ¶ ВҪГғВ°ВЈВҝВЎВјВӯ 10ВәДһВөГҡВҝВЎ В»Г§В¶ГіГҒДұВҙГҸВҙГҷ!') ON CONFLICT DO NOTHING;
