INSERT INTO quest_talk (i_num, str_talk) VALUES (45090, 'ВҫГ®ВјВӯВҝГҖВјВјВҝГӨ. 10ГҒГ–ВіГў ВҝВҘВәГӯВ·Ві ВұВіГҲВҜВұГҮГҖВ» В°В®В°Гӯ В°ГЁВҪГғВҙГҷВёГ©, ВҝГёГҮГҸВҙГӮ ВҝГүВјГҮГҖГҮ ВҝВҘВәГӯВ·ВіГҖВёВ·ГҺ ВұВіГҲВҜГҮГҳ ВөГҘВёВіВҙГҸВҙГҷ. ВҝГёГҮГҸВҙГӮ ВёЕһВҙВәВёВҰ ВјВұГ…ГғГҮГҸВҝВ© ГҒГ–ВјВјВҝГӨ') ON CONFLICT DO NOTHING;
INSERT INTO quest_talk (i_num, str_talk) VALUES (45091, 'ВҫГҲВіГ§ГҮГҸВјВјВҝГӨ [ГҖГҢВәВҘГҶВ® В°ГјВёВ®ГҖГҺ] ВҫГҶВјГӮГҖГ”ВҙГҸВҙГҷ. В°ГҰГҮГЁГ„ВЎ ГҮГ—ВҫГҶВёВ®ВҝВЎ ВҙГ«ГҮГ‘ ВәВёВ»ГіГҖВ» ГҮГҳВөГҘВёВ®В°Гӯ ГҖГ–ВҪГҖВҙГҸВҙГҷ. ГҮГ¶ГҖГ§ ГҒВўВјГ“ГҮГҳ ГҖГ–ВҙГӮ Г„ВіВёВҜГ…ГҚВ·ГҺ В°ГЁГҒВӨВіВ»ГҖГҮ ГҖГ–ВҙГӮ ВёДҹВөГ§ В°ГҰГҮГЁГ„ВЎ ВәВёВ»ГіГҖВ» В№ЕһГҖВёВҪГғВ°ГҡВҪГҖВҙГҸВұГ®?') ON CONFLICT DO NOTHING;
INSERT INTO quest_talk (i_num, str_talk) VALUES (45092, 'В°ГҰГҮГЁГ„ВЎ ВәВёВ»ГіГҖВ» В№ЕһГҖВёВҪГғВёГ© ВҙГҷВёВҘ Г„ВіВёВҜГ…ГҚВҝВЎ ВҙГҷВҪГғВҙГӮ В№ЕһГҖВё ВҪГҮ ВјГ¶ ВҫГёВҪГҖВҙГҸВҙГҷ. |В№ЕһГҖВёВҪГғВ°ГҡВҪГҖВҙГҸВұГ®?') ON CONFLICT DO NOTHING;
