INSERT INTO quest_talk (i_num, str_talk) VALUES (45257, 'ГҮГ¶ГҖГ§ В¶ГіГ…Г—ГҖГҢВіГ« ВҙГёГҖГјГҖГҢ ВҝГҖГҮГӮВҪГғВ°ВЈГҖГҢ ВҫГҶВҙГ•ВҙГҸВҙГҷ. ВҝГҖГҮГӮ ВҪГғВ°ВЈГҖВә ~ ВұГ®ГҒГ¶ГҖГ”ВҙГҸВҙГҷ.') ON CONFLICT DO NOTHING;
INSERT INTO quest_talk (i_num, str_talk) VALUES (45258, '[ВөГҘВ·ВЎВ°ГҜ В»ГіГҖГҡ]ВҝВЎВјВӯ ВіВӘВҝГӮ ВҫГҶГҖГҢВәВӨВҪВә & Г…В©В¶ГіГҖГҢВҪГғВҪВә 1000В°Ві ВұВіГҲВҜВұГҮГҖВ» ВҫГҶГҖГҢВәВӨВҪВә & Г…В©В¶ГіГҖГҢВҪГғВҪВә В№В°ВҫГ  1000В°ВіГӮВҘВёВ®В·ГҺ ВұВіГҲВҜ ГҮГҸВ°Гӯ ВҪГҚГҖВәВҪГ…В°ВЎВҝГӨ?') ON CONFLICT DO NOTHING;
INSERT INTO quest_talk (i_num, str_talk) VALUES (45259, '[ВөГҘВ·ВЎВ°ГҜ В»ГіГҖГҡ]ВҝВЎВјВӯ ВіВӘВҝГӮ ВҫГҶГҖГҢВәВӨВҪВә 1000В°Ві ВұВіГҲВҜВұГҮГҖВ» В°ВЎГҒГ¶В°Гӯ ВҝГҖВјГҢВұВәВҝГӨ ВұВіГҲВҜ ГҮГҸВҪГғВ°ГҡВҪГҖВҙГҸВұГ®?') ON CONFLICT DO NOTHING;
INSERT INTO quest_talk (i_num, str_talk) VALUES (45260, '[ВөГҘВ·ВЎВ°ГҜ В»ГіГҖГҡ]ВҝВЎВјВӯ ВіВӘВҝГӮ Г…В©В¶ГіГҖГҢВҪГғВҪВә1000В°Ві ВұВіГҲВҜВұГҮГҖВ» В°ВЎГҒГ¶В°Гӯ ВҝГҖВјГҢВұВәВҝГӨ ВұВіГҲВҜ ГҮГҸВҪГғВ°ГҡВҪГҖВҙГҸВұГ®?') ON CONFLICT DO NOTHING;
INSERT INTO quest_talk (i_num, str_talk) VALUES (45261, 'В№В°ВҫГ  ВұВіГҲВҜВұГҮГҖГҢ ГҖГҺВәВҘГ…ГӨВёВ®ВҝВЎ ВҫГёВҪГҖВҙГҸВҙГҷ ВҙГҷВҪГғ ГҲВ®ГҖГҺГҮГҳ ГҒГ–ВјВјВҝГӨ') ON CONFLICT DO NOTHING;
INSERT INTO quest_talk (i_num, str_talk) VALUES (45262, 'В¶ГіГ…Г—ГҖГҢВіГ« ВәГҺВёВ§ВҝВЎВјВӯ ВҫГІГҖВёВҪГ… ВҫГҶГҖГҢГ…ГӣГҖВ» В»ГЁГҒВҰГҮГҸВ°Гӯ ВҪГҚГҖВёВҪГғВұВәВҝГӨ? ВҫГ®В¶В°ГҮГ‘ ВҫГҶГҖГҢГ…ГӣГҖВ» В»ГЁГҒВҰ ГҮГҸВҪГғВ°ГҡВҪГҖВҙГҸВұГ®? *ГҖГҹВёГё В»ГЁГҒВҰ ГҮГҸВјГ…ВөВө ВәВ№ВұВёВ°ВЎ ВәГ’В°ВЎВҙГүГҮГ•ВҙГҸВҙГҷ*') ON CONFLICT DO NOTHING;
INSERT INTO quest_talk (i_num, str_talk) VALUES (45263, 'В№В«В»Гі В№Г¶ГҮГҒ ГҖГҢВҝГ«ВұГҮГҖВ» В»ГЁГҒВҰ ГҮГҸВҪГғВ°ГҡВҪГҖВҙГҸВұГ®? *ГҖГҹВёГё В»ГЁГҒВҰ ГҮГҸВјГ…ВөВө ВәВ№ВұВёВ°ВЎ ВәГ’В°ВЎВҙГүГҮГ•ВҙГҸВҙГҷ ВҪГ…ГҒГҹГҮГҸВ°Г” ГҲВ®ГҖГҺГҲГ„ ГҒВҰВ°Г… В№Г¶ГҶВ° ВҙВӯВ·ВҜГҒГ–ВјВјВҝГӨ*') ON CONFLICT DO NOTHING;
INSERT INTO quest_talk (i_num, str_talk) VALUES (45264, 'В№В«В»Гі ВҫГҶГҖГҢГ…Гӣ ВҙГ«ВҝВ©ВұГҮГҖВ» В»ГЁГҒВҰ ГҮГҸВҪГғВ°ГҡВҪГҖВҙГҸВұГ®? *ГҖГҹВёГё В»ГЁГҒВҰ ГҮГҸВјГ…ВөВө ВәВ№ВұВёВ°ВЎ ВәГ’В°ВЎВҙГүГҮГ•ВҙГҸВҙГҷ ВҪГ…ГҒГҹГҮГҸВ°Г” ГҲВ®ГҖГҺГҲГ„ ГҒВҰВ°Г… В№Г¶ГҶВ° ВҙВӯВ·ВҜГҒГ–ВјВјВҝГӨ*') ON CONFLICT DO NOTHING;
INSERT INTO quest_talk (i_num, str_talk) VALUES (45265, 'ГҒВӨВёВ» ГҒВҰВ°Г…ГҮГҸВҪГғВ°ГҡВҪГҖВҙГҸВұГ®?') ON CONFLICT DO NOTHING;
INSERT INTO quest_talk (i_num, str_talk) VALUES (45266, 'ГҒВҰВ°Г…ГҮГҳВҫГҹГҮГ’ ВҫГҶГҖГҢГ…ГӣГҖГҢ ВҫГёВҪГҖВҙГҸВҙГҷ. ГҖГҺВәВҘГ…ГӨВёВ® ГҲВ®ГҖГҺГҲГ„ ВҙГҷВҪГғ ВёВ»В°ГүВҫГ®ГҒГ–ВјВјВҝГӨ') ON CONFLICT DO NOTHING;
INSERT INTO quest_talk (i_num, str_talk) VALUES (45267, 'ВҝГёГҮГҸВҪГғВҙГӮ ВҫГҶГҖГҢГ…ГӣГҖВ» ГҒВҰВ°Г… ГҮГҳВөГҘВ·ГҲВҪГҖВҙГҸВҙГҷ. ГҒГұВ°Г…ВҝГ® ГҮГҸВ·Г§ ВәВёВіВ»ВјВјВҝГӨ') ON CONFLICT DO NOTHING;
INSERT INTO quest_talk (i_num, str_talk) VALUES (45268, 'Welcome! We have prepared multiple events for you to enjoy. Which one would you like to proceed with?') ON CONFLICT DO NOTHING;
INSERT INTO quest_talk (i_num, str_talk) VALUES (45269, 'ВәВ№ВұГҚГҖГҡ ГҖГҢВәВҘГҶВ®ВёВҰ ГҒГёГҮГ ГҮГҸВҪГҮВ·ГҒВ°Гӯ ГҮГҸВҪГғВҙГӮВұВәВҝГӨ! ВәВ№ВұГҚГҖГҡ ГҖГҢВәВҘГҶВ®ВҙГӮ Г„ВЈВұВё ГғГҹВ°ВЎВөГҲ ГҮГҳВҙГ§ВөГҮВҙГӮ ГҖВҜГҖГәВёВё uiВҝВЎ ВәВёГҖГҢВёГ§, ГғГҠВҙГ« ВёЕһВҪГғГҒГ¶ В¶ГҮВҙГӮ ВёЕһГҖГҸГҖВ» ВәВёВіВҫ ВјГ¶ ГҖГ–ВҪГҖВҙГҸВҙГҷ! ГҮГҸВ·Г§ВҝВЎ ГғГ–ВҙГ« 2В°ГЁГҒВӨВёВё ВәВёВіВҫ ВјГ¶ ГҖГ–ГҖВёВҙГҸ ВҪГ…ГҒГҹГҮГҸВ°Г” ВәВёВіВ»ГҒГ–ВҪГғВұГҰ В№ГҷВ¶ГёВҙГҸВҙГҷ. ГғГҠВҙГ« uiВёВҰ ВҝГҖГҮГӮ ГҮГҸВҪГғВ°ГҡВҪГҖВҙГҸВұГ®?') ON CONFLICT DO NOTHING;
INSERT INTO quest_talk (i_num, str_talk) VALUES (45270, 'В¶ГіГ…Г—ГҖГҢВіГ« ВҙГёГҖГјГҖВә 12ВҪГғ 40ВәДһ or 23ВҪГғ 30ВәДһВәГҺГ…ГҚ 40ВәДһВ°ВЈ ВҪГ…ГғВ» ГҮГҸВҪГҮ ВјГ¶ ГҖГ–ВҪГҖВҙГҸВҙГҷ. ГҒГ¶ВұД°ГҖВә ВҪГ…ГғВ» ВҪГғВ°ВЈГҖГҢ ВҫГҶВҙГ•ВҙГҸВҙГҷ.') ON CONFLICT DO NOTHING;
