INSERT INTO quest_talk (i_num, str_talk) VALUES (45284, 'Welcome, I have retired from fishing competition but I''m still fishing here and there. Are you interested in fishing?') ON CONFLICT DO NOTHING;
INSERT INTO quest_talk (i_num, str_talk) VALUES (45285, 'You have already learned how to fish from me.') ON CONFLICT DO NOTHING;
INSERT INTO quest_talk (i_num, str_talk) VALUES (45286, 'For fishing, you can go to a fishing spot in each area and use the space bar and arrow to go fishing. There is a required level for each fishing spot, so take a good look at it and fish in the fishing spot! You''re here for the first time, so I''ll send you to the Moradon Fishing Grounds. If you go to the Moradon Fishing Grounds, you''ll find [Fishing Manager] Fisher. Talk to Fisher and I''ll give you a reward.') ON CONFLICT DO NOTHING;
INSERT INTO quest_talk (i_num, str_talk) VALUES (45287, 'I can only teleport to Moradon Fishing Ground Once, so walk to Fisher. ') ON CONFLICT DO NOTHING;
INSERT INTO quest_talk (i_num, str_talk) VALUES (45288, 'You have already completed Quest.') ON CONFLICT DO NOTHING;
INSERT INTO quest_talk (i_num, str_talk) VALUES (45289, 'You are here to hear a story about fishing from a retired angler!!! Then I''ll give you a basic item so I can go fishing right away! Please make sure to empty the item space by 3 spaces.') ON CONFLICT DO NOTHING;
INSERT INTO quest_talk (i_num, str_talk) VALUES (45290, 'Insufficient inventory space.') ON CONFLICT DO NOTHING;
INSERT INTO quest_talk (i_num, str_talk) VALUES (45291, 'You received it. Enjoy Fishing!') ON CONFLICT DO NOTHING;
INSERT INTO quest_talk (i_num, str_talk) VALUES (45292, 'Your level is not enough. When you are above level 35, please come back.') ON CONFLICT DO NOTHING;
INSERT INTO quest_talk (i_num, str_talk) VALUES (45293, 'The current competitions are as follows. In the record competition menu, you can only see the ranking of the previous record competition.') ON CONFLICT DO NOTHING;
INSERT INTO quest_talk (i_num, str_talk) VALUES (45294, 'During the fishing competition, you can win the prize according to the ranking of the information written in the fishing handbook.') ON CONFLICT DO NOTHING;
INSERT INTO quest_talk (i_num, str_talk) VALUES (45295, 'Which of the record competitions would you like to see?') ON CONFLICT DO NOTHING;
INSERT INTO quest_talk (i_num, str_talk) VALUES (45296, 'Which daily competition would you like to see?') ON CONFLICT DO NOTHING;
INSERT INTO quest_talk (i_num, str_talk) VALUES (45297, 'Which competition would you like to see?') ON CONFLICT DO NOTHING;
INSERT INTO quest_talk (i_num, str_talk) VALUES (45298, 'As this is a first-come-first-served competition, we do not provide information on the current status.') ON CONFLICT DO NOTHING;
INSERT INTO quest_talk (i_num, str_talk) VALUES (45299, 'Hello~ You must be curious about fishing! |- What is fishing? -You must equip your main weapon with a fishing rod. |You must have a bait in your inventory.|You can purchase the bait from a fishing supply vendor in each fishing spot.|Press the space bar in the fishing spot to start fishing.|In the mini-game where the circle is reduced, the closer you get to the center, the more experience you will get after successful fishing.|Press the arrows displayed in the mini-game to decrease your stamina.|If you press the wrong arrows, the remaining time will decrease.|You can check the fish you caught in the Fishing Mastery, and your summary of fishing data in the Fishing Handbook.""""') ON CONFLICT DO NOTHING;
INSERT INTO quest_talk (i_num, str_talk) VALUES (45300, 'You caught a wanted fish today. I''ll give you a fishing score!') ON CONFLICT DO NOTHING;
INSERT INTO quest_talk (i_num, str_talk) VALUES (45301, 'You brought the ark of the constellation! This is the ark of the Constellation with a chance to drop a Holy Knight Armor Box! Would you like to open it?') ON CONFLICT DO NOTHING;
