INSERT INTO quest_talk (i_num, str_talk) VALUES (45316, 'ВҫГҲВіГ§ГҮГҸВјВјВҝГӨ В№В«В»Гі ВҙГ«ВҝВ© В№Г¶ГҮГҒВұГҮГҖВ» В°ВЎГҒГ¶В°Гӯ ВҝГҖВјГҢВұВәВҝГӨ. [ВұГўВ°ВЈГҒВҰ] В№В«В»Гі ВҙГ«ВҝВ© В№Г¶ГҮГҒВұГҮГҖВёВ·ГҺ ВҙГҷВҪГғ ВұВіГҲВҜГҮГҳВөГҘВёВ®В°Гӯ ГҖГ–ВҪГҖВҙГҸВҙГҷ. ВұВіГҲВҜ ГҮГҸГҒГ¶ ВҫГҠГҖВёВёГ© 3ВҝГ№ 15ГҖГҸ ГҒВЎВ°ГӢ ГҖГҢГҲГ„ [ВұГўВ°ВЈГҒВҰ] В№В«В»Гі ВҙГ«ВҝВ© В№Г¶ГҮГҒВұГҮГҖВёВ·ГҺ ВұВіГҲВҜ ГҮГҸГҒГ¶ ВҫГҠГҖВә В№В«В»Гі ВҙГ«ВҝВ© В№Г¶ГҮГҒВұГҮГҖВә ГҒВҰВ°Г…ВөГӢВҙГҸВҙГҷ. ГҒГ–ГҖГҮГҮГҸВҪГғВұГҰ В№ГҷВ¶ГёВҙГҸВҙГҷ! ВұВіГҲВҜ ГҮГҸВҪГғВ°ГҡВҪГҖВҙГҸВұГ®?') ON CONFLICT DO NOTHING;
INSERT INTO quest_talk (i_num, str_talk) VALUES (45317, 'В№В«В»Гі ВҙГ«ВҝВ© В№Г¶ГҮГҒВұГҮГҖГҢ ГҖГҺВәВҘГ…ГӨВёВ®ВҝВЎ ВҫГёВҪГҖВҙГҸВҙГҷ ВҙГҷВҪГғ ГҖГҺВәВҘГ…ГӨВёВ® ГҲВ®ГҖГҺГҲГ„ ВёВ»ГҖВ» В°ГүВҫГ®ГҒГ–ВјВјВҝГӨ') ON CONFLICT DO NOTHING;
INSERT INTO quest_talk (i_num, str_talk) VALUES (45318, '[ВұГўВ°ВЈГҒВҰ] В№В«В»Гі ВҙГ«ВҝВ© В№Г¶ГҮГҒВұГҮГҖВёВ·ГҺ ВұВіГҲВҜГҮГҳВөГҘВ·ГҲВҪГҖВҙГҸВҙГҷ! ВұГўВ°ВЈВҝВЎ ГҖВҜГҖГҮГҮГҸВҝВ© В»Г§ВҝГ«ГҮГҳГҒГ–ВҪГғВұГҰ В№ГҷВ¶ГёВҙГҸВҙГҷ!') ON CONFLICT DO NOTHING;
INSERT INTO quest_talk (i_num, str_talk) VALUES (45319, 'ВјГ’ГҒГ¶ГҮГҸВ°Гӯ В°ГЁВҪГ… ВҫГҶГҖГҢГ…ГӣГҖВә [ВұГўВ°ВЈГҒВҰ] В№В«В»Гі ВҙГ«ВҝВ© В№Г¶ГҮГҒВұГҮ ГҖГ”ВҙГҸВҙГҷ. ГҖГҢВ№ГҢ ВұВіГҲВҜВ№ЕһГҖВёВјГҢВҪГҖВҙГҸВҙГҷ') ON CONFLICT DO NOTHING;
INSERT INTO quest_talk (i_num, str_talk) VALUES (45320, 'В»Г§ВҝГ«ГҮГҸГҒГ¶ВҫГҠГҖВә ВҫГҶГҖГҢГ…ГӣГҖВ» ВұВіГҲВҜВұГҮГҖВёВ·ГҺ ВұВіГҲВҜГҮГҳВөГҘВёВіВҙГҸВҙГҷ! ВұВіГҲВҜ ГҮГҸВҪГғВ°ГҡВҪГҖВҙГҸВұГ®?') ON CONFLICT DO NOTHING;
INSERT INTO quest_talk (i_num, str_talk) VALUES (45321, 'В»Г§ВҝГ«ГҮГ‘ ГҲГ§ГҖГ»ГҖГҢ ВіВІВҫГҶГҖГ–ВҪГҖВҙГҸВҙГҷ! 1В°ВіВ¶ГіВөВө В»Г§ВҝГ«ВҪГғ ВұВіГҲВҜВұГҮГҖВёВ·ГҺ ВұВіГҲВҜГҖГҢ ВәГ’В°ВЎВҙГүГҮГ•ВҙГҸВҙГҷ ГӮГјВ°Гӯ ВәГҺГ…В№ВөГҘВёВіВҙГҸВҙГҷ') ON CONFLICT DO NOTHING;
INSERT INTO quest_talk (i_num, str_talk) VALUES (45322, 'ВұВіГҲВҜВұГҮГҖВёВ·ГҺ ВұВіГҲВҜГҮГҳВөГҘВ·ГҲВҪГҖВҙГҸВҙГҷ ГҖГҺВәВҘГ…ГӨВёВ®ВёВҰ ГҲВ®ГҖГҺГҮГҳВәВёВјВјВҝГӨ!') ON CONFLICT DO NOTHING;
