INSERT INTO quest_talk (i_num, str_talk) VALUES (45357, 'В°ГұВөГҘ ВөГҘВ·ВЎВ°ГҜ В»ГіГҖГҡВ°ВЎ ВҫГёГҖВёВҪГғВұВәВҝГӨ. ВөГҘВ·ВЎВ°ГҜ В»ГіГҖГҡВҙГӮ ГҶГ„ВҝГ¶ЛңЕһГҖВ» Г…Г«ГҮГҳ ВұВёВёГ…ГҮГҸВҪГҮ ВјГ¶ ГҖГ–ВҪГҖВҙГҸВҙГҷ.') ON CONFLICT DO NOTHING;
INSERT INTO quest_talk (i_num, str_talk) VALUES (45358, '[В°ГұВөГҘ ВөГҘВ·ВЎВ°ГҜ В»ГіГҖГҡ]ВёВҰ ГҲВ®ГҖГҺГҮГҳ ВәВёВҫГ’ВҪГҖВҙГҸВҙГҷ.|ГҖГҢВ·Вұ ВҫГҶГҖГҢГ…ГӣГҖГҢ ВіВӘВҝГ”ВіГ—ВҝГӨ.|ВҝВ©ВұГў ГҖГ–ВҪГҖВҙГҸВҙГҷ.') ON CONFLICT DO NOTHING;
INSERT INTO quest_talk (i_num, str_talk) VALUES (45359, 'В°ВЎВ№ГҰГҖГҮ В°ГёВ°ВЈГҖГҢ 2Г„Вӯ ГҖГҢВ»Гі ГҮГҠВҝГӨ ГҮГ•ВҙГҸВҙГҷ.|В°ВЎВ№ГҰГҖГҮ В°ГёВ°ВЈГҖВ» ГҲВ®ВәВёГҮГҳ ГҒГ–ВјВјВҝГӨ.') ON CONFLICT DO NOTHING;
