INSERT INTO quest_talk (i_num, str_talk) VALUES (45362, 'Defeat 200 enemies. You must defeat them after accepting the quest. Make sure that it''s those 200 enemies in the center area of Ronark Land. If you give up the quest, you''ll have to defeat 200 enemies from the beginning again, so be aware. Are you ready now?') ON CONFLICT DO NOTHING;
INSERT INTO quest_talk (i_num, str_talk) VALUES (45363, 'Have you captured 200 enemies yet?') ON CONFLICT DO NOTHING;
INSERT INTO quest_talk (i_num, str_talk) VALUES (45364, 'Let''s see. You''re satisfied with your third rebirth.') ON CONFLICT DO NOTHING;
INSERT INTO quest_talk (i_num, str_talk) VALUES (45365, 'You are currently in the third rebirth process. If you give up the quest in the middle of it, you''ll have to defeat 200 enemies all over and once you accept the quest, and you rebirth with Noah, quest will disappear automatically.') ON CONFLICT DO NOTHING;
INSERT INTO quest_talk (i_num, str_talk) VALUES (45366, 'You haven''t defeated all 200 enemies yet.') ON CONFLICT DO NOTHING;
INSERT INTO quest_talk (i_num, str_talk) VALUES (45367, 'The second rebirth needs 200 million Noah. Come back when you have it all.') ON CONFLICT DO NOTHING;
INSERT INTO quest_talk (i_num, str_talk) VALUES (45368, 'You don''t seem to have the amount I''ve asked for. For the second rebirth, you will need 200 million noah.') ON CONFLICT DO NOTHING;
INSERT INTO quest_talk (i_num, str_talk) VALUES (45369, 'Yes, it''s for sure that you have 200 million noah. Good job. When you''re ready to take the last test, Proof of Honor, come back to me. Oh, I almost forgot, I''ll take that 200 million noah.') ON CONFLICT DO NOTHING;
INSERT INTO quest_talk (i_num, str_talk) VALUES (45370, 'The final test, the Proof of Honor, has two ways to complete it. 1. Defeat 200 enemies from Ronark Land Center area, 2. Rebirth with 500 million noah.  Choose carefully.') ON CONFLICT DO NOTHING;
INSERT INTO quest_talk (i_num, str_talk) VALUES (45371, 'This long, long journey is over! Here are the qualifications for rebirth. Come back to me when you are ready for the next life. The reborn body is much stronger than your present body. Oh yes, I''ll take this 500 million noah.') ON CONFLICT DO NOTHING;
INSERT INTO quest_talk (i_num, str_talk) VALUES (45372, 'ВҫГ®ВјВӯВҝГҖВјВјВҝГӨ~ ГҮГҒВёВ®В№ГҢВҫГ¶ ГҖВҜГҖГәГҖГҢВҪГғВёГ© ВөГҘВ·В№ГҖГҢГ…В© В°ВЎГҲВЈВ¶Г» ВёВ¶В№Дұ В°ГёВ°Д° ГҒГөВ°ВЎ ГҒГ–В№В®ВјВӯВёВҰ ВҙГң ГҮГ‘В№Гё ВөГҘВёВ®В°ГӯГҖГ–ВҪГҖВҙГҸВҙГҷ! В№ЕһГҖВёВҪГғВ°ГҡВҪГҖВҙГҸВұГ®? В№ЕһГҖВёВҪГҮВ¶В© ГҖГҺВәВҘГ…ГӨВёВ® 2Г„ВӯГҖВ» ВәГұВҝГ¶ГҒГ–ВјВјВҝГӨ~') ON CONFLICT DO NOTHING;
INSERT INTO quest_talk (i_num, str_talk) VALUES (45373, 'ГҮГҒВёВ®В№ГҢВҫГ¶ ГҖВҜГҖГәВ°ВЎ ВҫГҶВҙГҸВҝВЎВҝВ© ГҲВ®ГҖГҺ ГҲГ„ ВҙГҷВҪГғ ВҙГ«ГҲВӯВ°ГүВҫГ®ГҒГ–ВјВјВҝГӨ~') ON CONFLICT DO NOTHING;
INSERT INTO quest_talk (i_num, str_talk) VALUES (45374, 'ГҮГҒВёВ®В№ГҢВҫГ¶ ГҖВҜГҖГәВҪГғВұВәВҝГӨ! ВҝВ©ВұГў ГҖГ–ВҪГҖВҙГҸВҙГҷ!') ON CONFLICT DO NOTHING;
INSERT INTO quest_talk (i_num, str_talk) VALUES (45375, 'В°ГұВөГҘ ВөГҘВ·ВЎВ°ГҜ В»ГіГҖГҡВёВҰ В°ВЎГҒГ¶В°ГӯВҝГҖВјГҢВұВәВҝГӨ! 1В°ВіВ¶Г» 5В°Ві ГҒГҹ ВҫГ®ВҙГҖ ВҫГҶГҖГҢГ…ГӣГҖВ» В°ВЎГҒГ¶В°Гӯ В°ГЁВҪГ…В°ВЎВҝВ©?') ON CONFLICT DO NOTHING;
INSERT INTO quest_talk (i_num, str_talk) VALUES (45376, 'You don''t have enough noah. If you want to prove your honor with Noah, bring me 500 million noah.') ON CONFLICT DO NOTHING;
INSERT INTO quest_talk (i_num, str_talk) VALUES (45377, 'Bring me your 500 million noah.') ON CONFLICT DO NOTHING;
INSERT INTO quest_talk (i_num, str_talk) VALUES (45378, 'Welcome! Would you like to purchase Prayer of Priests [Limited Edition]? It can only be purchased and used by priests, and it is a prayer that has 5% enhancement of the normal prayers. It''s a bundle of 30 and once you use one, it lasts for 30 minutes. The price is 30 million Noah. Would you like to purchase it? ') ON CONFLICT DO NOTHING;
INSERT INTO quest_talk (i_num, str_talk) VALUES (45379, 'You are not a priest. Only the Priest class can make the purchase.') ON CONFLICT DO NOTHING;
INSERT INTO quest_talk (i_num, str_talk) VALUES (45380, 'В°ГұВөГҘ ВөГҘВ·ВЎВ°ГҜ В»ГіГҖГҡ В¶ГҮВҙГӮ В°ГұВөГҘ ВөГҘВ·ВЎВ°ГҜX5В»ГіГҖГҡВ°ВЎ ГҖГ–ГҖВёВҪГғВұВәВҝГӨ! ВҫГ®ВҙГҖ ВҫГҶГҖГҢГ…ГӣГҖВ» В°ВЎГҒГ¶В°Гӯ ВұВіГҲВҜ ГҮГҸВҪГғВ°ГҡВҪГҖВҙГҸВұГ®?') ON CONFLICT DO NOTHING;
INSERT INTO quest_talk (i_num, str_talk) VALUES (45381, 'ВҫГ®ВјВӯВҝГҖВјВјВҝГӨ~ ГҮГ ВҝГ®ГҖГҮ ВіГ—ГҖГҷГ…В¬В·ГҺВ№Г¶ВёВҰ В°ВЎГҒГ¶В°Гӯ ВҝГҖВјГҢВіВӘВҝГӨ! ГҮГ ВҝГ®ГҖГҮ ВіГ—ГҖГҷГ…В¬В·ГҺВ№Г¶ГҖГҺ ВёВёГ…Вӯ ВҝГ«В»Г§ВҙГ”ВҝВЎВ°Г” ГҮГ ВҝГ®ГҖГҢ ВұГӘВөГ©ВұГҰ В№ГҷВ¶ГёВҙГҸВҙГҷ! ГҮГ ВҝГ®ГҖГҮ ВіГ—ГҖГҷГ…В¬В·ГҺВ№Г¶ВёВҰ В»Г§ВҝГ« ГҮГҸВҪГғВ°ГҡВҪГҖВҙГҸВұГ®?') ON CONFLICT DO NOTHING;
INSERT INTO quest_talk (i_num, str_talk) VALUES (45382, 'ГҖГҺВәВҘГ…ГӨВёВ®ВҝВЎ ГҮГ ВҝГ®ГҖГҮ ВіГ—ГҖГҷГ…В¬В·ГҺВ№Г¶В°ВЎ ВҫГёВҙГӮВ°ГҚ В°В°ВҫГҶВҝГӨ ВҙГҷВҪГғ ГҲВ®ГҖГҺГҮГҸВ°Гӯ ВҙГ«ГҲВӯВ°ГүВҫГ®ГҒГ–ВјВјВҝГӨ') ON CONFLICT DO NOTHING;
INSERT INTO quest_talk (i_num, str_talk) VALUES (45383, '[В°ВЎГҒВӨГҖГҮ ВҙЕһ]ГҖВ» ВёГӮВҫГҶ В°ВЁВ»Г§ГҮГҸВҙГӮ ВёВ¶ГҖВҪГҖВёВ·ГҺ ГҖГҢВәВҘГҶВ® ВұГўВ°ВЈВөВҝВҫГҲ ВөГј ГҮГ‘В№Гё ВҫГҶВұГўВөГҘВ·ВЎВ°ГҜГҖВ» ГғВіГ„ВЎ ГҲГ„ ВҝГҖВ·В»ГҒГ¶ГҮГў ВҫГ§ГҶГ„ 10В°ВіВёВҰ ГҖГәГҮГ‘Г…Г— В°ВЎГҒВ®ВҙГҷ ГҒГ–ВҪГғВёГ© ВёВ№ГҖВә ВҫГҶГҖГҢГ…ГӣГҖВ» ВөГҘВёВ®В°Гӯ ГҖГ–ВҫГ®ВҝГӨ! |ГҖГҺВәВҘГ…ГӨВёВ® 8Г„ВӯГҖВ» ВәГұВҝГ¶ГҒГ–ВјВјВҝГӨ! ВҫГҶГҖГҢГ…ГӣГҖВ» В°ВЎГҒГ¶В°Гӯ ВҝГҖВјГҢВіВӘВҝГӨ? |<font color=@#660066@>*ГҖГҢВәВҘГҶВ® ВұГўВ°ВЈВөВҝВҫГҲ ВөГј ГҮГ‘В№Гё ВҫГҶГҖГҢГ…ГӣГҖВ» В№ЕһВҫГҶ В°ВЎВҪГҮВјГ¶ ГҖГ–ВҪГҖВҙГҸВҙГҷ.') ON CONFLICT DO NOTHING;
INSERT INTO quest_talk (i_num, str_talk) VALUES (45384, 'Not enough spaces in inventory.') ON CONFLICT DO NOTHING;
INSERT INTO quest_talk (i_num, str_talk) VALUES (45385, 'Hello, thank you for your support for Knight Online. We have an event which you can receive a special item per account. Bring an emblem called, I Love Knight Online, from Akara Altar to exchange it for various special items. Would you like to proceed with it?') ON CONFLICT DO NOTHING;
INSERT INTO quest_talk (i_num, str_talk) VALUES (45386, 'A warm welcome to the warrior who have been chosen for the message of Logos. I''m White Knight -White. Logos which was crouching in the Bifrost has resumed it''s activity. You must step forward for Adonis Continent. ') ON CONFLICT DO NOTHING;
INSERT INTO quest_talk (i_num, str_talk) VALUES (45387, 'We will provide various supplies to the heroes who have the Call of Logos. You need at least 16 inventory spaces, and after receiving the supply, you will receive additional supplies once you reach level 70 or higher.') ON CONFLICT DO NOTHING;
INSERT INTO quest_talk (i_num, str_talk) VALUES (45388, 'We will provide various supplies to the heroes who have the Call of Logos. You need at least 17 inventory spaces, and after receiving the supply, you will receive additional supplies once you reach level 70 or higher.') ON CONFLICT DO NOTHING;
INSERT INTO quest_talk (i_num, str_talk) VALUES (45389, 'You do not have enough inventory space.') ON CONFLICT DO NOTHING;
INSERT INTO quest_talk (i_num, str_talk) VALUES (45390, 'You don''t have the item in the inventory. Please check.') ON CONFLICT DO NOTHING;
INSERT INTO quest_talk (i_num, str_talk) VALUES (45391, 'You have to be at least level 70 to receive the item. Come back once you reach level 70.') ON CONFLICT DO NOTHING;
INSERT INTO quest_talk (i_num, str_talk) VALUES (45392, 'It''s been given.') ON CONFLICT DO NOTHING;
INSERT INTO quest_talk (i_num, str_talk) VALUES (45393, '7 x [Dark Mithril Piece] and 3,000,000 Noah will be used to craft 7th Armor Piece. Which piece of armor do you wish to receive?') ON CONFLICT DO NOTHING;
INSERT INTO quest_talk (i_num, str_talk) VALUES (45394, 'ВҫГҶГ„В«В¶ГіГҖГҮ ВҫГҮВјВјВјВӯВёВ®В»ГіГҖГҡВёВҰ В°ВЎГҒГ¶В°Гӯ ВҝГҖВјГҢВұВәВҝГӨ! ВҝГҖГҮГӮ ГҮГҸВҪГғВ°ГҡВҪГҖВҙГҸВұГ®?!') ON CONFLICT DO NOTHING;
INSERT INTO quest_talk (i_num, str_talk) VALUES (45395, 'ВҫГҶГ„В«В¶ГіГҖГҮ ВҫГҮВјВјВјВӯВёВ® В»ГіГҖГҡВ°ВЎ ВҫГёВҪГҖВҙГҸВҙГҷ. ГҖГҺВәВҘГ…ГӨВёВ®ВёВҰ ВҙГҷВҪГғ ГҲВ®ГҖГҺГҮГҳГҒГ–ВјВјВҝГӨ') ON CONFLICT DO NOTHING;
INSERT INTO quest_talk (i_num, str_talk) VALUES (45396, 'Warrior! We have obtained an urgent information that a large number of our enemies have appeared in the central area of Ronark land. Please help us again. ') ON CONFLICT DO NOTHING;
INSERT INTO quest_talk (i_num, str_talk) VALUES (45397, 'Please defeat 50 enemies in the central area of Ronarkland.*You must kill them inside the Ronarkland Monument, and it is not possible to continue with the Mithril Quest at the same time. You will also need to have the Battle Order in order to complete the quest. ') ON CONFLICT DO NOTHING;
INSERT INTO quest_talk (i_num, str_talk) VALUES (45398, 'You have not defeated all 50 enemies. Please talk to me again once it''s done.') ON CONFLICT DO NOTHING;
INSERT INTO quest_talk (i_num, str_talk) VALUES (45399, 'In order to complete Defeat 50 Enemies quest, you will need to receive a Battle Order from me. *Battle Order expires in 12 hrs, so you will need to complete the quest within 12 hrs. ') ON CONFLICT DO NOTHING;
INSERT INTO quest_talk (i_num, str_talk) VALUES (45400, 'Here''s the Battle Order for you. Once you have this, you''ll activate the quest, Defeat 50 Enemies. *Battle Order will expire in 12 hrs, so complete the quest within 12 hrs.') ON CONFLICT DO NOTHING;
INSERT INTO quest_talk (i_num, str_talk) VALUES (45401, 'You do NOT have the Battle Order. Go get one, and come back.') ON CONFLICT DO NOTHING;
INSERT INTO quest_talk (i_num, str_talk) VALUES (45402, 'You have already received the Battle Order with a different character. Please check again.') ON CONFLICT DO NOTHING;
INSERT INTO quest_talk (i_num, str_talk) VALUES (45403, 'it is not possible to continue with the Green Mithril Quest') ON CONFLICT DO NOTHING;
INSERT INTO quest_talk (i_num, str_talk) VALUES (45404, 'it is not possible to continue with the defeated all 50 enemies Quest') ON CONFLICT DO NOTHING;
INSERT INTO quest_talk (i_num, str_talk) VALUES (45405, 'You have already resurrected 15 times. I won''t help you with the next resurrection because one more might destroy your soul.') ON CONFLICT DO NOTHING;
INSERT INTO quest_talk (i_num, str_talk) VALUES (45406, 'You have already resurrected 15 times. I won''t help you with the next resurrection because one more might destroy your soul.') ON CONFLICT DO NOTHING;
INSERT INTO quest_talk (i_num, str_talk) VALUES (45407, 'To celebrate [Knight Online 19th Anniversary] you can receive a lot of awesome items if you defeat overly blessed plants and bring me 10 Onions with Orange scent. | Please make sure there''s 8 spaces in inventory. Did you bring the items? | <font color=@#660066@>*You can receive these items once during the event period.') ON CONFLICT DO NOTHING;
INSERT INTO quest_talk (i_num, str_talk) VALUES (45408, 'Redistribution Scroll - You would like to trade this untradable item for a 30 days War Hero''s Wings. Would you like to exchange it?') ON CONFLICT DO NOTHING;
INSERT INTO quest_talk (i_num, str_talk) VALUES (45409, 'What exchange voucher would you like to get for the War Hero''s Wings? ') ON CONFLICT DO NOTHING;
INSERT INTO quest_talk (i_num, str_talk) VALUES (45410, 'I''m afraid that is not what I asked for...') ON CONFLICT DO NOTHING;
INSERT INTO quest_talk (i_num, str_talk) VALUES (45411, 'ГғГ ГҮГҸВөГҘВ·ГҒВҝГӨ. ГҖДұГҒВӨ ГҒГ¶ГҒВё Г…ВёГҖГҢГҶВІГҖВ» ГҲВ№ВөГҰ ГҮГҸВјГҢВҫГ®ВҝГӨ. 20ВіГў ВөВҝВҫГҲ ВіВӘГҖГҢГҶВ®ВёВҰ В»Г§В¶Г»ГҮГҳ ГҒГ–ВјГ…ВјВӯ В°ВЁВ»Г§ГҮГҳВҝГӨ') ON CONFLICT DO NOTHING;
INSERT INTO quest_talk (i_num, str_talk) VALUES (45412, 'Application for participating Forgotten Temple has been completed. Please note that you must be in Moradon at the time of entrance to be automatically entered. Also, if you do not have 100,000 Noah, automatic admission will be cancelled. ') ON CONFLICT DO NOTHING;
INSERT INTO quest_talk (i_num, str_talk) VALUES (45413, 'Participation for the Forgotten Temple Application has already been completed. Please note that if you are not present at your castle at the time of entrance, your automatic admission will be cancelled. ') ON CONFLICT DO NOTHING;
INSERT INTO quest_talk (i_num, str_talk) VALUES (45414, 'The Forgotten Temple has already started, therefore you cannot apply for participation.') ON CONFLICT DO NOTHING;
INSERT INTO quest_talk (i_num, str_talk) VALUES (45415, 'You did not apply to participate for the Forgotten Temple, or you were not selected for participation.') ON CONFLICT DO NOTHING;
INSERT INTO quest_talk (i_num, str_talk) VALUES (45416, 'Application for participating Under the Castle has been completed. Please come during the Under the Castle opening hours and start the talk to enter.') ON CONFLICT DO NOTHING;
INSERT INTO quest_talk (i_num, str_talk) VALUES (45417, 'Only those who have been selected to participate for Under the Castle can enter at the moment. Please try to start the talk again after 5 minutes.') ON CONFLICT DO NOTHING;
INSERT INTO quest_talk (i_num, str_talk) VALUES (45418, 'Application for participating Under the Castle has already been completed.') ON CONFLICT DO NOTHING;
INSERT INTO quest_talk (i_num, str_talk) VALUES (45419, 'Will you enter Under the Castle?') ON CONFLICT DO NOTHING;
INSERT INTO quest_talk (i_num, str_talk) VALUES (45420, 'Will you apply to enter Under the Castle?') ON CONFLICT DO NOTHING;
INSERT INTO quest_talk (i_num, str_talk) VALUES (45421, 'Under the Castle has started already, therefore, you will need to apply again with normal users.') ON CONFLICT DO NOTHING;
INSERT INTO quest_talk (i_num, str_talk) VALUES (45422, 'You have brought Manes'' Marbles! Which item would you like to exchange for?') ON CONFLICT DO NOTHING;
INSERT INTO quest_talk (i_num, str_talk) VALUES (45423, 'You cannot apply as the IP is used to apply from a different character.') ON CONFLICT DO NOTHING;
INSERT INTO quest_talk (i_num, str_talk) VALUES (45424, 'Would you like to apply with this character as the Server''s best of the best character? ') ON CONFLICT DO NOTHING;
INSERT INTO quest_talk (i_num, str_talk) VALUES (45425, 'How to enter Forgotten Temple 1. Between 1:55 - 1:59 OR 20:55 - 20:59, click NPC to proceed with the menu for participating to enter the Forgotten Temple. (Once the application is completed, there''s a message that shows it''s complete) 2. You will be automatically entered when the Forgotten Temple opens at 2 and 21:00 only If you are selected as first-come, first serve (50%) or Random (50%). If your character is not in Moradon area, they will not teleport to event area.') ON CONFLICT DO NOTHING;
INSERT INTO quest_talk (i_num, str_talk) VALUES (45426, 'How to enter Under the Castle 1. Between 19:55 and 19:59 click on the How to enter Under the Castle menu on the NPC to apply for admission. (If the application menu is clicked again after completing the application, a message indicating that the """"Application has been Completed"""" will be displayed.) 2. Those who gets selected as first-come, first serve (50%) or Randomly (50%) will be automatically enetered to Under the Castle at it''s opening time 20:00 The rest can enter after 5 min. 3. After 22:05 the existing Under the Castle entrance method will be applied so you can enter freely. If your character is not in Moradon area, they will not teleport to event area.') ON CONFLICT DO NOTHING;
INSERT INTO quest_talk (i_num, str_talk) VALUES (45427, 'There are no cumulative warnings to reset.') ON CONFLICT DO NOTHING;
INSERT INTO quest_talk (i_num, str_talk) VALUES (45428, 'There are not enough Noah to reset the cumulative warnings.') ON CONFLICT DO NOTHING;
INSERT INTO quest_talk (i_num, str_talk) VALUES (45429, 'Would you like to reset the Juraid cumulative warning? You need 10 million noahs to reset.') ON CONFLICT DO NOTHING;
INSERT INTO quest_talk (i_num, str_talk) VALUES (45430, 'You cannot enter because there are 10 accumulated warnings. Please reset warning and apply for admission.') ON CONFLICT DO NOTHING;
INSERT INTO quest_talk (i_num, str_talk) VALUES (45431, 'The cumulative warning has been reset.') ON CONFLICT DO NOTHING;
INSERT INTO quest_talk (i_num, str_talk) VALUES (45432, 'How to enter Forgotten Temple 1. Between 00:55 - 00:59 OR 15:55 - 15:59, click NPC to proceed with the menu for participating to enter the Forgotten Temple. (Once the application is completed, there''s a message that shows it''s complete) 2. You will be automatically entered when the Forgotten Temple opens at 01 and 16:00 only If you are selected as first-come, first serve (50%) or Random (50%). If your character is not in Moradon area, they will not teleport to event area.') ON CONFLICT DO NOTHING;
INSERT INTO quest_talk (i_num, str_talk) VALUES (45433, 'How to enter Under the Castle 1. Between 16:55 and 16:59 click on the How to enter Under the Castle menu on the NPC to apply for admission. (If the application menu is clicked again after completing the application, a message indicating that the """"Application has been Completed"""" will be displayed.) 2. Those who gets selected as first-come, first serve (50%) or Randomly (50%) will be automatically enetered to Under the Castle at it''s opening time 17:00. The rest can enter after 5 min. 3. After 17:05 the existing Under the Castle entrance method will be applied so you can enter freely. If your character is not in Moradon area, they will not teleport to event area.') ON CONFLICT DO NOTHING;
INSERT INTO quest_talk (i_num, str_talk) VALUES (45434, 'Are you ready to enter? | Only those permitted (Level 46~59 and above) can participate in the Forgotten Temple at 00, 16 PM.') ON CONFLICT DO NOTHING;
INSERT INTO quest_talk (i_num, str_talk) VALUES (45435, 'Draki Title Exchange Solar Tattoo (30 Days)') ON CONFLICT DO NOTHING;
INSERT INTO quest_talk (i_num, str_talk) VALUES (45436, 'Draki Title Exchange Solar Tattoo (30 Days)') ON CONFLICT DO NOTHING;
INSERT INTO quest_talk (i_num, str_talk) VALUES (45437, 'I''m afraid that is not what I asked for...') ON CONFLICT DO NOTHING;
INSERT INTO quest_talk (i_num, str_talk) VALUES (45438, 'I''m afraid that is not what I asked for...') ON CONFLICT DO NOTHING;
INSERT INTO quest_talk (i_num, str_talk) VALUES (45439, 'For under the castle you can enter only on Fridays between the hours of 17 and 21 hours. You can''t enter any other times.') ON CONFLICT DO NOTHING;
INSERT INTO quest_talk (i_num, str_talk) VALUES (45440, 'You cannot apply as the IP is used to apply from a different character.') ON CONFLICT DO NOTHING;
INSERT INTO quest_talk (i_num, str_talk) VALUES (45441, 'ГҖГҢ ГҲГ»ГҖВә ВәГҖГҖГҺГҖГҢ ВөГҮВҫГ®ВјВӯ ВҙГө ГҖГҢВ»Гі В»Г§ВҝГ« ГҮГ’ ВјГ¶ ВҫГёВҙГҷ.') ON CONFLICT DO NOTHING;
INSERT INTO quest_talk (i_num, str_talk) VALUES (45442, 'Application for participating Twisted Moradon has already been completed.') ON CONFLICT DO NOTHING;
INSERT INTO quest_talk (i_num, str_talk) VALUES (45443, 'You must be level 80 or above to enter Twisted Moradon') ON CONFLICT DO NOTHING;
INSERT INTO quest_talk (i_num, str_talk) VALUES (45444, 'You will need 10 million Noah in order to remove 1 penalty point. Please note that you will remove ALL Points all at once.') ON CONFLICT DO NOTHING;
INSERT INTO quest_talk (i_num, str_talk) VALUES (45445, 'Are you sure you want to remove all the penalty points?') ON CONFLICT DO NOTHING;
