INSERT INTO quest_talk (i_num, str_talk) VALUES (45465, 'ВҙГҷВёВҘ Г„ВіВёВҜГ…ГҚВ·ГҺ ГҒГёГҮГ  ГҒГҹГҖГҢВҪГғВ°Г…ВіВӘ ГҖГҢВ№ГҢ ВҝГҸВ·ГЎГҮГҸВјГҢВҪГҖВҙГҸВҙГҷ~ ВҙГҷВҪГғ ГҲВ®ГҖГҺ ГҲГ„ ВҙГ«ГҲВӯВёВҰ В°ГүВҫГ®ГҒГ–ВјВјВҝГӨ') ON CONFLICT DO NOTHING;
