INSERT INTO quest_talk (i_num, str_talk) VALUES (45478, 'Welcome~ White Day is coming! Which event would you like to proceed with?') ON CONFLICT DO NOTHING;
INSERT INTO quest_talk (i_num, str_talk) VALUES (45479, 'There is a man who always confesses to beautiful women! The woman asked me for help, and she said that I will give her a gift if the warrior will help him not to confess her!') ON CONFLICT DO NOTHING;
INSERT INTO quest_talk (i_num, str_talk) VALUES (45480, 'When you defeat a man who confesses, there is a certain probability of dropping candy ingredients! Could you bring me 20 candy ingredients?') ON CONFLICT DO NOTHING;
