INSERT INTO quest_talk (i_num, str_talk) VALUES (45482, 'Warrior! On this White Day prepare a gift for your loved ones! When you defeat the man you want to confess to, there is a chance that a candy basket will drop. If you bring 10 of them, you will receive a bouquet of flowers and a flower shield for 14 days!') ON CONFLICT DO NOTHING;
