INSERT INTO quest_talk (i_num, str_talk) VALUES (45484, 'Did you bring the items I mentioned?') ON CONFLICT DO NOTHING;
INSERT INTO quest_talk (i_num, str_talk) VALUES (45485, 'Welcome! Do you want to get a Talisman of Courage through the Talisman Draw? A Talisman of Courage will drop with a low probability! Contaminated Holy Water 1 ~ 50 will be given randomly! It consumes 9 million Noah to draw once. Would you like to draw?') ON CONFLICT DO NOTHING;
INSERT INTO quest_talk (i_num, str_talk) VALUES (45486, 'Once again, enemy nations are threatening us! If you kill 50 enemies so that our Elmorad can win, we will give you the 7th armor or contaminated Holy Water. One part of the 7th armor will be dropped with a low probability, and contaminated Holy Water is given randomly among 1-10.') ON CONFLICT DO NOTHING;
INSERT INTO quest_talk (i_num, str_talk) VALUES (45487, 'Will you kill 50 Karus? * Simultaneous progress with Mithril Quest and 50 Kill Quest is not possible.') ON CONFLICT DO NOTHING;
INSERT INTO quest_talk (i_num, str_talk) VALUES (45488, 'You haven''t defeatd all the required enemies. Afte you''re done, talk to me.') ON CONFLICT DO NOTHING;
INSERT INTO quest_talk (i_num, str_talk) VALUES (45489, 'Once again, enemy nations are threatening us! If you kill 50 enemies so that our Karus can win, we will give you the 7th armor or contaminated Holy Water. One part of the 7th armor will be dropped with a low probability, and contaminated Holy Water is given randomly among 1-10.') ON CONFLICT DO NOTHING;
