INSERT INTO quest_talk (i_num, str_talk) VALUES (45491, 'You came to get the order for the 50 kill quest! You can only receive one character per account, and you must clear the quest within 12 hours. Please note that you cannot clear the quest without items. * Simultaneous progress with Mithril Quest and 50 Kill Quest is not possible.') ON CONFLICT DO NOTHING;
INSERT INTO quest_talk (i_num, str_talk) VALUES (45492, 'Welcome! We have Unique Monster Summon Staff for sale! You can purchase it for 29 million Noah, and when you use the Unique Monster Summon Staff, monsters are summoned and items drop when you defeat them! Would you like to purchase it?') ON CONFLICT DO NOTHING;
