INSERT INTO quest_talk (i_num, str_talk) VALUES (45494, 'Did you bring 20 candy baskets?!') ON CONFLICT DO NOTHING;
INSERT INTO quest_talk (i_num, str_talk) VALUES (45495, 'Where would you like to go?') ON CONFLICT DO NOTHING;
INSERT INTO quest_talk (i_num, str_talk) VALUES (45496, 'Warrior! Moradon''s front yard is suddenly overgrown with wild grass and plants can''t grow! Can you bring me just 40 wild grass for 10 gems of EXP, Contribution, Life jewels each as well as Fire Dragon Wings (7 Days).') ON CONFLICT DO NOTHING;
