INSERT INTO quest_talk (i_num, str_talk) VALUES (45503, 'Welcome, Now''s the time to register to participate the Battle of Champion: Lord of Chaos. Registration times are 02:50 - 03:00, 14:50 - 15:00. Would you like to register?') ON CONFLICT DO NOTHING;
INSERT INTO quest_talk (i_num, str_talk) VALUES (45504, 'ВҫГ®ВјВӯВҝГҖВјВјВҝВ©~ ГҮГ ВҝГ®ГҖГҮ ВҝВҘВәГӯВ·Ві ВұВіГҲВҜВұГҮГҖВ» В»Г§ВҝГ«ГҮГҸВ·ВҜ ВҝГҖВјГҢВұВәВҝГӨ! В·ВЈВҙДұГҖВёВ·ГҺ ВёДҹВөГ« ВҝВҘВәГӯВ·ВіГҒГҹ ГҮГҸВіВӘВёВҰ ВҫГІГҖВёВҪГҮВјГ¶ ГҖГ–ВҪГҖВҙГҸВҙГҷ! ВұВіГҲВҜ ГҮГҸВҪГғВ°ГҡВҪГҖВҙГҸВұГ®?') ON CONFLICT DO NOTHING;
INSERT INTO quest_talk (i_num, str_talk) VALUES (45505, 'You do not have premium. You need 500 ladder points to enter Under the Castle. 1. 500 Ladder Points will be deducted when applying for admission to Under the Castle 10 minutes in advance. * Please note that even if you apply for admission again, 500 will be deducted. 2. 500 ladder points will be deducted when applied users enter first-come-first-served basis after 10 minutes of entry.') ON CONFLICT DO NOTHING;
INSERT INTO quest_talk (i_num, str_talk) VALUES (45506, 'Due to insufficient monthly ladder 500 points') ON CONFLICT DO NOTHING;
