INSERT INTO quest_talk (i_num, str_talk) VALUES (45508, '54ГҖГҢВәВҘГҶВ® ВұГўВіГӨГҖВёВ·ГҺ ВҫГҶВјГӮ ВәВҜВҪГ… ГҒГ–В№В®ВјВӯВёВҰ ВөГҘВёВ®В°Гӯ ГҖГ–ВҪГҖВҙГҸВҙГҷ! В°Г”ГҒВӨВҙГ§ 1ГҲВё ГҒГ¶ВұЕһВҪГҖВҙГҸВҙГҷ! ГҮГҳВҙГ§ Г„ВіВёВҜГ…ГҚВ·ГҺ В№ЕһГҖВёВҪГғВ°ГҡВҪГҖВҙГҸВұГ®?!') ON CONFLICT DO NOTHING;
