INSERT INTO quest_talk (i_num, str_talk) VALUES (45510, 'Welcome! Do you want to get a Talisman of Spirit through the Talisman Draw? A Talisman of Courage will drop with a low probability! Contaminated Holy Water 1 ~ 50 will be given randomly! It consumes 9 million Noah to draw once. Would you like to draw?') ON CONFLICT DO NOTHING;
INSERT INTO quest_talk (i_num, str_talk) VALUES (45511, 'Welcome! You came for a Talisman Enhancement Scroll! You can purchase 3 Talisman Enhancement Scrolls with 6 million Noah or 1 Talisman Enhancement Scroll with 20 Talisman Pieces. Which one would you like to purchase?') ON CONFLICT DO NOTHING;
INSERT INTO quest_talk (i_num, str_talk) VALUES (45512, 'You would like to purchase a box that might contain Garges weapon! It''s 7 million Noah and it is a box that comes out with a certain probability of Garges Weapon and other items. Would you like to purchase it?') ON CONFLICT DO NOTHING;
