INSERT INTO quest_talk (i_num, str_talk) VALUES (45514, 'Once again, enemy nations are threatening us! If you kill 50 enemies so that our Elmorad can win, we will give you the 8th armor or contaminated Holy Water. One part of the 8th armor will be dropped with a low probability, and contaminated Holy Water is given randomly among 1-10.') ON CONFLICT DO NOTHING;
