INSERT INTO quest_talk (i_num, str_talk) VALUES (45541, 'How to Enter Under the Castle: 1. Enter between 19:55 - 19:59 by clicking the new menu button on the NPC to apply to enter. (Once the application is completed, even if you click on the menu button, it''ll just say the Application has been completed) 2. When Under the Castle opens at 20:00, 50% first come first serve, 50% of random users will be able to enter. Noone after that can enter.') ON CONFLICT DO NOTHING;
