INSERT INTO quest_talk (i_num, str_talk) VALUES (45588, 'ВҫГ®ВјВӯВҝГҖВјВјВҝГӨ! В°ВЎГҖГҢВҫГҶГҖГҮ ВјВұВ№В°ГҖВ» В°ВЎГҒГ¶В°Гӯ ВҝГҖВјГҢВіВӘВҝГӨ?! В°ВЎГҖГҢВҫГҶГҖГҮ ВјВұВ№В°ГҖВ» ВҝГҖГҮГӮГҮГҸВёГ© ВҙГҷВҫГ§ГҮГ‘ ВҫГҶГҖГҢГ…ГӣГҒГҹ ГҮГҸВіВӘВёВҰ ГҲВ№ВөГҰГҮГ’ ВјГ¶ ГҖГ–ВҪГҖВҙГҸВҙГҷ! В°ВЎГҖГҢВҫГҶГҖГҮ ВјВұВ№В° ВҝГҖГҮГӮВҪГғ ГҖГҸГҒВӨ ГҲВ®В·ГјВ·ГҺ В°ВЎГҖГҢВҫГҶГҖГҮ ВјВұВ№В° ГҒВ¶В°ВўГҖВ» ВөГҘВёВ®ВҙГӮВөВҘВҝГӨ! ГҮГҳВҙГ§ ГҒВ¶В°ВўГҖВ» В°ВЎГҒГ¶В°ГӯВҝГҖВёГ© ВҙГҷВёВҘ ВҫГҶГҖГҢГ…ГӣГҖВёВ·ГҺ ВұВіГҲВҜГҮГҳВөГҘВёВ®В°ГӯГҖГ–ВҪГҖВҙГҸВҙГҷ!') ON CONFLICT DO NOTHING;
INSERT INTO quest_talk (i_num, str_talk) VALUES (45589, 'В°ВЎГҖГҢВҫГҶГҖГҮ ВјВұВ№В° ГҒВ¶В°ВўГҖВ» В°ВЎГҒГ¶В°Гӯ ВҝГҖВјГҢВіВӘВҝГӨ?! ВҫГ®В¶ВІ ВҫГҶГҖГҢГ…ГӣГҖВёВ·ГҺ ВұВіГҲВҜ ГҮГҸВҪГғВ°ГҡВҪГҖВҙГҸВұГ®?') ON CONFLICT DO NOTHING;
INSERT INTO quest_talk (i_num, str_talk) VALUES (45590, 'В°ВЎГҖГҢВҫГҶГҖГҮ ВјВұВ№В° ГҒВ¶В°Вў В°ВіВјГ¶В°ВЎ ВәГҺГҒВ·ГҮГ•ВҙГҸВҙГҷ. ГҖГҺВәВҘГ…ГӨВёВ®ВёВҰ ГҲВ®ГҖГҺГҮГҳГҒГ–ВјВјВҝГӨ') ON CONFLICT DO NOTHING;
INSERT INTO quest_talk (i_num, str_talk) VALUES (45591, 'В°ВЎГҖГҢВҫГҶГҖГҮ ВјВұВ№В° or В°ВЎГҖГҢВҫГҶГҖГҮ ВјВұВ№В° ГҒВ¶В°ВўГҖВ» В°ВЎГҒГ¶В°Гӯ ВҝГҖВјГҢВіВӘВҝГӨ?! ВҫГ®В¶ВІВ°Гү В°ВЎГҒГ¶В°ГӯВҝГҖВјГҢВіВӘВҝГӨ? *В°ВЎГҖГҢВҫГҶГҖГҮ ВјВұВ№В°ГҖВ» ВҝГҖГҮГӮГҮГҸВұГў ГҖВ§ГҮГҳВјВӯВҙГӮ ГҖГҺВәВҘГ…ГӨВёВ® 5Г„ВӯГҖГҮ ВәГіГ„ВӯГҖГҢ ГҮГҠВҝГӨГҮГ•ВҙГҸВҙГҷ.') ON CONFLICT DO NOTHING;
