INSERT INTO quest_talk (i_num, str_talk) VALUES (45629, 'ВұВіГҲВҜГҮГҳВөГҘВ·ГҲВҪГҖВҙГҸВҙГҷ! ГҒГҒГҖВә В°ГЎВ°ГәВ°ВЎ ГҖГ–ГҖВёВҪГғВұГҰ!') ON CONFLICT DO NOTHING;
INSERT INTO quest_talk (i_num, str_talk) VALUES (45630, '<font color=@#660066@>1ВҫГҜ ВіГ«ВҫГҶВёВҰ</font>ВёВҰ <font color=@#660066@>ВұВ№В°ВЎ ГҖГҢГҒГ– ГҲВ®ГҖГҺГҒГө</font>ГҖВёВ·ГҺ В№ГҷВІГҷВ°Г” ВөГҮВёГ© 24ВҪГғВ°ВЈВіВ»ВҝВЎ ГҖГҢГҒГ–ВёВҰ ГҒГёГҮГ ГҮГҳВҫГҹ ГҮГ‘ВҙГҷВіГ—. ВұВіГҲВҜ ГҲГ„, ГҖГҢГҒГ– ВёЕһВҙВәВёВҰ ВҙВ©ВёВЈВ°Г”.') ON CONFLICT DO NOTHING;
INSERT INTO quest_talk (i_num, str_talk) VALUES (45631, 'ГҲВ®ВҪГҮГҲГ· <font color=@#660066@>1ВҫГҜ ВіГ«ВҫГҶ</font>В·ГҺВұВә') ON CONFLICT DO NOTHING;
INSERT INTO quest_talk (i_num, str_talk) VALUES (45632, 'ГҲГ¬..ВұВ№В°ВЎ ГҖГҢГҒГ– ГҖГҢВәВҘГҶВ®ВёВҰ ГҮГҸВ·ГҒВёГ© <font color=@#660066@>1ВҫГҜ ВіГ«ВҫГҶ</font>ВёВҰ В°ВЎГҒВ®ВҝГҚВҫГҹГҮГҸВіГ—. ГҲВ®ГҖГҺГҲГ„ В°ВЎГҒВ®ВҝГҖВ°Г”.') ON CONFLICT DO NOTHING;
INSERT INTO quest_talk (i_num, str_talk) VALUES (45633, 'ВұГ—В·Ві <font color=@#660066@>1ВҫГҜ ВіГ«ВҫГҶ</font>ВёВҰ ВұВ№В°ВЎ ГҖГҢГҒГ–ВёВҰ ГҮГҸВҙГӮВөВҘ ГҮГҠВҝГӨГҮГ‘ ВҫГҶГҖГҢГ…ГӣВөГ©В·ГҺ В№ГҷВІГЈВјВӯ ГҒГ¶ВұЕһГҮГҳГҒГ–В°ГҡВіГ—, ВёДҹВөГ§ ГҒГҳВәГұВёВҰ ВёВ¶ГғГҶВіВӘ?') ON CONFLICT DO NOTHING;
INSERT INTO quest_talk (i_num, str_talk) VALUES (45634, '1В°ВӯГҲВӯ 7ВјВјГҶВ® ГҖГҘВәГұ ВұВіГҲВҜВұГҮГҖВ» ВөГ©В°Гӯ ВҝГҖВјГҢВіГ—ВҝГӨ? ВҫГ®В¶ВІ ГҖГҘВәГұВ·ГҺ ВұВіГҲВҜГҮГҸВҪГғВ°ГҡВҪГҖВҙГҸВұГ®?') ON CONFLICT DO NOTHING;
INSERT INTO quest_talk (i_num, str_talk) VALUES (45635, '1В°ВӯГҲВӯ 7ВјВјГҶВ® ГҖГҘВәГұ ВұВіГҲВҜВұГҮГҖГҢ ВҫГёВҪГҖВҙГҸВҙГҷ. ГҖГҺВәВҘГ…ГӨВёВ® ГҲВ®ГҖГҺ ГҲГ„ ВҙГҷВҪГғ ВҙГ«ГҲВӯ В°ГүВҫГ®ГҒГ–ВјВјВҝГӨ') ON CONFLICT DO NOTHING;
INSERT INTO quest_talk (i_num, str_talk) VALUES (45636, 'ГҖГҚВјГҒВјГ…ВіГҺ В№В«ВұГў ВұВіГҲВҜВұГҮГҖВ» ВөГ©В°Гӯ ВҝГҖВјГҢВіГ—ВҝГӨ? ВҫГ®В¶ВІ ГҖГҘВәГұВ·ГҺ ВұВіГҲВҜ ГҮГҸВҪГғВ°ГҡВҪГҖВҙГҸВұГ®?') ON CONFLICT DO NOTHING;
INSERT INTO quest_talk (i_num, str_talk) VALUES (45637, 'ГҖГҚВјГҒВјГ…ВіГҺ В№В«ВұГў ВұВіГҲВҜВұГҮГҖГҢ ВҫГёВҪГҖВҙГҸВҙГҷ. ГҖГҺВәВҘГ…ГӨВёВ® ГҲВ®ГҖГҺ ГҲГ„ ВҙГҷВҪГғ ВҙГ«ГҲВӯ В°ГүВҫГ®ГҒГ–ВјВјВҝГӨ') ON CONFLICT DO NOTHING;
INSERT INTO quest_talk (i_num, str_talk) VALUES (45638, 'ГҖГҚВјГҒВјГ…ВіГҺ В№В«ВұГў ВұВіГҲВҜВұГҮГҖГҢ ВҫГёВҪГҖВҙГҸВҙГҷ. ГҖГҺВәВҘГ…ГӨВёВ® ГҲВ®ГҖГҺ ГҲГ„ ВҙГҷВҪГғ ВҙГ«ГҲВӯ В°ГүВҫГ®ГҒГ–ВјВјВҝГӨ') ON CONFLICT DO NOTHING;
