INSERT INTO quest_talk (i_num, str_talk) VALUES (45673, 'ВҫГ®ВјВӯВҝГҖВјВјВҝГӨ В°ГҰГҮГЁГҖГҮ ВәВёВјВ® 100ВёВё ВіГ«ВҫГҶ, В№ГҰВҫГ®ГҖГҮВәВёВјВ®, В»ДұВёГӯГҖГҮВәВёВјВ®, ВұГўВҝВ©ГҖГҮ ВәВёВјВ®ГҖВә В°ВіВҙГ§ 60ВёВё ВіГ«ВҫГҶ, В№В«ВұГў ГҖГҺГғВҫГҶВ® ГҒГ–В№В®ВјВӯ, В№ГҰВҫГ®ВұВё ГҖГҺГғВҫГҶВ® ГҒГ–В№В®ВјВӯ В°ВіВҙГ§ 25ВёВё ВіГ«ВҫГҶ, ГӮДұВҪГ’В¶Вұ 50ВёВё ВіГ«ВҫГҶ, ВҝГ¬ГҲВІ ГғВ»ВҪГүГҲВҜ 20ВёВё ВіГ«ВҫГҶВҝВЎ ГҶГҮВёГ…ГҮГҸВ°ГӯГҖГ–ВҪГҖВҙГҸВҙГҷ. ВҫГ®ВҙГҖ ВҫГҶГҖГҢГ…ГӣГҖВёВ·ГҺ ВұВёВёГ… ГҮГҸВҪГғВ°ГҡВҪГҖВҙГҸВұГ®?') ON CONFLICT DO NOTHING;
INSERT INTO quest_talk (i_num, str_talk) VALUES (45674, 'Would you like to open a box that contains Ring of the Felankor? In addition to Ring of the Felankor, you can also obtain other items. Would you like to open the box? *It costs 15 million Noah to open the box.') ON CONFLICT DO NOTHING;
