INSERT INTO quest_talk (i_num, str_talk) VALUES (45681, 'ВәВёВ»ГіГҖВ» ГҖГҢВ№ГҢ В№ЕһВҫГҶВ°ВЎВјГҢВҫГ®ВҝВ©!') ON CONFLICT DO NOTHING;
