INSERT INTO quest_talk (i_num, str_talk) VALUES (45688, 'ВҫГ®ВјВӯВҝГҖВјВјВҝГӨ В°ВЎГҖГҢВҫГҶГҖГҮ ВјВұВ№В° ГҒВ¶В°Вў 250В°ВіВёВҰ В°ВЎГҒГ¶В°Гӯ ВҝГҖВҪГғВёГ© ВҝГёГҮГҸВҙГӮ ГҲГҰВ»Г§ГҖГҡВ№В«ВұГў В»ГіГҖГҡ ГҒГҹ 1В°ВіВ·ГҺ ВұВіГҲВҜГҮГҳВөГҘВёВіВҙГҸВҙГҷ! ВҫГ®ВҙГҖ В№В«ВұГўВ·ГҺ ВұВіГҲВҜГҮГҸВҪГғВ°ГҡВҪГҖВҙГҸВұГ®?') ON CONFLICT DO NOTHING;
INSERT INTO quest_talk (i_num, str_talk) VALUES (45689, '[ГҲГҰВ»Г§ГҖГҡ] ВҙГ«В°Г…ВёВҰ ВҝГёГҮГҸВҪГғВҙГӮВұВәВҝГӨ! ВјВұВ№В°ГҒВ¶В°Вў 250В°ВіВ·ГҺ ВұВіГҲВҜ ГҮГҸВҪГғВ°ГҡВҪГҖВҙГҸВұГ®?') ON CONFLICT DO NOTHING;
INSERT INTO quest_talk (i_num, str_talk) VALUES (45690, '[ГҲГҰВ»Г§ГҖГҡ] ВҫГ—ВҪВәВёВҰ ВҝГёГҮГҸВҪГғВҙГӮВұВәВҝГӨ! ВјВұВ№В°ГҒВ¶В°Вў 250В°ВіВ·ГҺ ВұВіГҲВҜ ГҮГҸВҪГғВ°ГҡВҪГҖВҙГҸВұГ®?') ON CONFLICT DO NOTHING;
INSERT INTO quest_talk (i_num, str_talk) VALUES (45691, '[ГҲГҰВ»Г§ГҖГҡ] ГҖГҘГғВўВёВҰ ВҝГёГҮГҸВҪГғВҙГӮВұВәВҝГӨ! ВјВұВ№В°ГҒВ¶В°Вў 250В°ВіВ·ГҺ ВұВіГҲВҜ ГҮГҸВҪГғВ°ГҡВҪГҖВҙГҸВұГ®?') ON CONFLICT DO NOTHING;
