INSERT INTO quest_talk (i_num, str_talk) VALUES (45759, 'ГҲГҰВ»Г§ГҖГҡ В№В«ВұГў ВұВіГҲВҜВұГҮГҖВ» В°ВЎГҒГ¶В°Гӯ ВҝГҖВјГҢВіВӘВҝГӨ?! ВҫГ®В¶ВІ В№В«ВұГўВ·ГҺ ВұВіГҲВҜГҮГҸВҪГғВ°ГҡВҫГ®ВҝГӨ?') ON CONFLICT DO NOTHING;
INSERT INTO quest_talk (i_num, str_talk) VALUES (45760, 'ГҒГ—ГҖВәГҖГҡГҖГҮВ°ГӢГҖВ» 100ВёВё ВіГ«ВҫГҶВҝВЎ ВұВёВёГ… ГҮГҸВҪГғВ°ГҡВҪГҖВҙГҸВұГ®?') ON CONFLICT DO NOTHING;
INSERT INTO quest_talk (i_num, str_talk) VALUES (45761, 'ВҫДҹВҙГөВҙГөГ„ВіВҪВҪ ГҖГ”ГҖГҘГҮГҸВұГў В№Г¶ГҶВ° Г…В¬ВёВҜ ВҪГғ Г„ВёГғВӯ ВҪГғВҪВәГ…ГӣUIВ°ВЎ ВҝГҖГҮГӮВөГӢВҙГҸВҙГҷ. ВҝГҖГҮГӮ ГҲГ„ ВјВәВ°ГёГҖГ»ГҖВёВ·ГҺ ГҖГ”В·ГӮГҮГҸВ°Г” ВөГҮВёГ©, ВҫДҹВҙГөВҙГөГ„ВіВҪВҪ ГҖГ”ГҖГҘ В°ВЎВҙГү ВҝВ©ВәГҺВҝВЎ ВөГ»В¶ГіВјВӯ ВҪГ…ГғВ» ВјВәВ°ГёГҮГҸВ°Г…ВіВӘ ГҖГ”ГҖГҘ or ВҪГҮГҶДһВөГӢВҙГҸВҙГҷ.') ON CONFLICT DO NOTHING;
INSERT INTO quest_talk (i_num, str_talk) VALUES (45762, '[ГҲВІВұД° ВҪВәГҖВ§Г„ВӘ ГҮГҒВёВ®В№ГҢВҫГ¶]ГҮДұГ…ГғГҖВ» В№ЕһГҖВёВҪГғВ°ГҡВҪГҖВҙГҸВұГ®? ГҲВІВұД° ВҪВәГҖВ§Г„ВӘ ГҮГҒВёВ®В№ГҢВҫГ¶ ГҖГ»ВҝГ« ВҪГғ ГҲВІВұД° В°Г®ВұВӘГҖГҢ, ГҲВІВұД° ВіВ¬ВҪГӢВҙГ« ВұВіГҲВҜВұГҮГҖВ» ГҒГ¶ВұЕһГҮГ•ВҙГҸВҙГҷ.') ON CONFLICT DO NOTHING;
INSERT INTO quest_talk (i_num, str_talk) VALUES (45763, 'You wish to buy Magic Warehouse Ticket (100 pieces) for 200 M Noah? This item allows you to store certain normally non-storable items in storage. Each time an item is stored, one ticket will be deducted. Stored items can be stored until withdrawn without any time limit.') ON CONFLICT DO NOTHING;
